      HOLY_BOOK,
      HOLY_BOOK_OR,
      UNHOLY_BOOK,
      UNHOLY_BOOK_OR,
      BOOK_OF_BALANCE,
      BOOK_OF_BALANCE_OR,
      BOOK_OF_WAR,
      BOOK_OF_WAR_OR,
      BOOK_OF_LAW,
      BOOK_OF_LAW_OR,
      BOOK_OF_DARKNESS,
      BOOK_OF_DARKNESS_OR,
      SOULFLAME_HORN
  );

