package org.willocon.gielinortravels;

import com.google.gson.Gson;
import com.google.gson.JsonObject;
import java.awt.image.BufferedImage;
import java.io.IOException;
import java.net.URL;
import javax.imageio.ImageIO;
import javax.inject.Inject;
import lombok.extern.slf4j.Slf4j;
import okhttp3.Call;
import okhttp3.Callback;
import okhttp3.MediaType;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;
import okio.BufferedSource;

@Slf4j
public class SSEImageClient
{

	private final OkHttpClient client;
	private final Gson gson;

	@Inject
	public SSEImageClient(OkHttpClient client, Gson gson)
	{
		this.client = client;
		this.gson = gson;
	}

	// CHANGE THIS TO SERVER: https://gielinortravels.containers.uwcs.co.uk
	private static final String BASE_URL = "https://gielinortravels.containers.uwcs.co.uk";

	private static BufferedImage downloadedImage;
	private static String downloadedCsv;

	// Downloads image from URL
	public static BufferedImage loadImage(String url) throws IOException
	{
		return ImageIO.read(new URL(url));
	}

	// Sends POST /join
	public void joinQueue(String userId, String username)
	{
		String json = "{\"user_id\":\"" + userId + "\" , \"username\":\"" + username + "\"}";

		RequestBody body = RequestBody.create(
			MediaType.parse("application/json"), json
		);

		Request request = new Request.Builder()
			.url(BASE_URL + "/join")
			.post(body)
			.build();

		client.newCall(request).enqueue(new Callback()
		{
			@Override
			public void onFailure(Call call, IOException e)
			{
				log.error("Failed to join queue: {}", e.getMessage());
				e.printStackTrace();
			}

			@Override
			public void onResponse(Call call, Response response) throws IOException
			{
				if (response.body() != null)
				{
					log.debug("Joined: {}", response.body().string());
				}
				response.close();
			}
		});
	}

	//Sends POST /leave
	public void leaveQueue(String userId)
	{
		String json = "{\"user_id\":\"" + userId + "\"}";

		RequestBody body = RequestBody.create(
			MediaType.parse("application/json"), json
		);

		Request request = new Request.Builder()
			.url(BASE_URL + "/leave")
			.post(body)
			.build();

		client.newCall(request).enqueue(new Callback()
		{
			@Override
			public void onFailure(Call call, IOException e)
			{
				log.error("Failed to leave queue: {}", e.getMessage());
				e.printStackTrace();
			}

			@Override
			public void onResponse(Call call, Response response) throws IOException
			{
				if (response.body() != null)
				{
					log.debug("Left: {}", response.body().string());
				}
				response.close();
			}
		});
	}

	// Sends POST /completed
	public void SendCompleted(String userId, String username, GielinorTravelsPlugin plugin)
	{
		String json = "{\"user_id\":\"" + userId + "\" , \"username\":\"" + username + "\"}";

		RequestBody body = RequestBody.create(
			MediaType.parse("application/json"), json
		);

		Request request = new Request.Builder()
			.url(BASE_URL + "/completed")
			.post(body)
			.build();

		client.newCall(request).enqueue(new Callback()
		{
			@Override
			public void onFailure(Call call, IOException e)
			{
				log.error("Failed to send completed: {}", e.getMessage());
				e.printStackTrace();
			}

			@Override
			public void onResponse(Call call, Response response) throws IOException
			{
				if (response.body() != null)
				{
					String responseJson = response.body().string();
					log.debug("Completed: {}", responseJson);
					JsonObject obj = gson.fromJson(responseJson, JsonObject.class);

					if (!obj.has("score"))
					{
						log.debug("No score in response, user already completed");
						return;
					}
					String score = obj.get("score").getAsString();
					log.debug("Score received: {}", score);

					if(obj.has("message") && obj.get("message").getAsString().equals("winner"))
					{
						log.debug("Winner!");
						plugin.displayWinner();
					}
					plugin.displayScore(score);
				}
				response.close();
			}
		});
	}

	// Opens SSE event stream
	public void listenForImageEvents(String userId, GielinorTravelsPanel panel)
	{
		Request request = new Request.Builder()
			.url(BASE_URL + "/events?user_id=" + userId)
			.get()
			.build();

		client.newCall(request).enqueue(new Callback()
		{

			@Override
			public void onFailure(Call call, IOException e)
			{
				log.error("SSE connection failed: {}", e.getMessage());
			}

			@Override
			public void onResponse(Call call, Response response) throws IOException
			{
				log.debug("Connected to SSE... waiting for image events");

				assert response.body() != null;
				BufferedSource source = response.body().source();

				while (!source.exhausted())
				{
					String line = source.readUtf8Line();

					if (line == null)
					{
						continue;
					}

					if (line.startsWith("data: "))
					{
						String json = line.substring(6);
						log.debug("Received SSE: {}", json);

						//handleEvent();
						JsonObject obj = gson.fromJson(json, JsonObject.class);
						if (obj.has("time"))
						{
							int secondsUntilNext = 601 - obj.get("time").getAsInt(); // extra second allows server time to update
							log.debug("Seconds until next event: {}", secondsUntilNext);
							panel.setTimeUntilNext(secondsUntilNext);
						}
						if (obj.has("difficulty" ))
						{
							int difficulty = obj.get("difficulty").getAsInt();
							log.debug("Difficulty: {}", difficulty);
							panel.setDifficulty(difficulty);
						}
						panel.onSSE();
					}
				}
			}
		});
	}

	// Handles incoming SSE JSON event using Gson - downloads image and CSV asynchronously
	public void handleEvent(Runnable onComplete)
	{
		String imageRelative = "/images/screenshot.png";
		String csvRelative = "/images/coords.csv";

		String imageUrl = BASE_URL + imageRelative;
		String csvUrl = BASE_URL + csvRelative;

		log.debug("Loading image: " + imageUrl);
		log.debug("Downloading CSV: " + csvUrl);

		// Download CSV asynchronously
		Request csvRequest = new Request.Builder().url(csvUrl).build();
		client.newCall(csvRequest).enqueue(new Callback()
		{
			@Override
			public void onFailure(Call call, IOException e)
			{
				log.error("Failed to download CSV: " + e.getMessage());
				e.printStackTrace();
			}

			@Override
			public void onResponse(Call call, Response response) throws IOException
			{
				if (response.body() != null)
				{
					downloadedCsv = response.body().string();
					log.debug("Loaded csv data: " + downloadedCsv);

					// Now download the image asynchronously
					try
					{
						downloadedImage = loadImage(imageUrl);
						log.debug("Loaded image: " + downloadedImage.getWidth() + "x" + downloadedImage.getHeight());

						// Call the completion callback
						if (onComplete != null)
						{
							onComplete.run();
						}
					}
					catch (IOException e)
					{
						log.error("Failed to download image: " + e.getMessage());
						e.printStackTrace();
					}
				}
				response.close();
			}
		});
	}

	public BufferedImage getDownloadedImage()
	{
		return downloadedImage;
	}

	public String getDownloadedCsv()
	{
		return downloadedCsv;
	}


}

