package org.willocon.gielinortravels;

import com.google.inject.Provides;
import java.awt.image.BufferedImage;
import javax.inject.Inject;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.ChatMessageType;
import net.runelite.api.Client;
import net.runelite.api.coords.WorldPoint;
import net.runelite.api.events.GameTick;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.Subscribe;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.ui.ClientToolbar;
import net.runelite.client.ui.NavigationButton;
import net.runelite.client.ui.overlay.OverlayManager;
import net.runelite.client.util.ImageUtil;

@Slf4j
@PluginDescriptor(
	name = "Gielinor Travels",
	description = "A location-based puzzle and time trial plugin for Old School RuneScape!",
	tags = {"gielinor", "travels", "location", "puzzle", "time trial", "overlay", "geoguessr", "Gieli Guessr"}
)
public class GielinorTravelsPlugin extends Plugin
{
	public GielinorTravelsPanel panel;
	@Inject
	Client client;
	@Inject
	private ClientThread clientThread;
	@Inject
	private GielinorTravelsConfig config;
	@Inject
	private ClientToolbar clientToolbar;
	@Inject
	private OverlayManager overlayManager;
	@Inject
	private LocationOverlay overlay;
	@Inject
	private SSEImageClient sseImageClient;
	private NavigationButton navButton;
	private WorldPoint destination;

	//Overlay logic
	private boolean showOverlayImage = false;
	private int ticksRemaining;

	// Found logic
	private boolean isFound = false;

	// tick counter for time until next location update
	private long tickCounter = 0;

	// array to hold a 5x5 grid of world points around the destination to reduce the chances of unwinnable locations being generated
	private WorldPoint[] surroundingPoints = new WorldPoint[25];


	@Override
	protected void startUp()
	{
		overlayManager.add(overlay);

		panel = new GielinorTravelsPanel(this, sseImageClient);

		final BufferedImage icon = ImageUtil.loadImageResource(GielinorTravelsPlugin.class, "/icon.png");

		navButton = NavigationButton.builder()
			.tooltip("Gielinor Travels")
			.icon(icon)
			.priority(30)
			.panel(panel)
			.build();

		clientToolbar.addNavigation(navButton);

		setDestination(new WorldPoint(3245, 3225, 0));

		log.info("Gielinor Travels started!");
	}

	@Override
	protected void shutDown()
	{
		overlayManager.remove(overlay);
		clientToolbar.removeNavigation(navButton);
		panel.leaveQueue();
		panel = null;
		log.info("Gielinor Travels stopped!");
	}

	@Subscribe
	public void onGameTick(GameTick tick)
	{
		tickCounter++;
		final WorldPoint playerPos = client.getLocalPlayer().getWorldLocation();
		if (!isFound)
		{
			if (isPlayerInSurrounding(playerPos))
			{
				isFound = true;
				// send some sort of packet to the server notifying it's been found
				panel.panelSendCompleted(
					client.getAccountHash() + "",
					client.getLocalPlayer().getName(),
					this
				);
			}
		}
		if (showOverlayImage)
		{
			ticksRemaining--;
			isFound = false;
			if (ticksRemaining <= 0)
			{
				showOverlayImage = false;
			}
		}
		panel.updateTimeUntilNext(tickCounter);
	}

	private boolean isPlayerInSurrounding(WorldPoint playerPos)
	{
		for (WorldPoint point : surroundingPoints)
		{
			if (playerPos.equals(point))
			{
				return true;
			}
		}
		return false;
	}

	public void displayScore(String score)
	{
		clientThread.invoke(() -> client.addChatMessage(ChatMessageType.GAMEMESSAGE, "", "You reached the destination! You got " + score + " points!", null));
	}

	public void displayWinner()
	{
		clientThread.invoke(() -> client.addChatMessage(ChatMessageType.GAMEMESSAGE, "", "Congratulations! You were the first to reach the destination!", null));
	}

	public void oneMinuteWarning()
	{
		clientThread.invoke(() -> client.addChatMessage(ChatMessageType.GAMEMESSAGE, "", "1 minute until next location update!", null));
	}

	// legacy method, kept for possible future use
	public void showLocation()
	{
		clientThread.invoke(() -> {
			if (client.getLocalPlayer() == null)
			{
				return;
			}
			WorldPoint playerPos = client.getLocalPlayer().getWorldLocation();
			String coords = String.format("X: %d, Y: %d, Plane: %d", playerPos.getX(), playerPos.getY(), playerPos.getPlane());
			client.addChatMessage(ChatMessageType.GAMEMESSAGE, "", "Current co-ord: " + coords, null);

		});
	}

	public WorldPoint getDestination()
	{
		return destination;
	}

	public void setDestination(WorldPoint newDestination)
	{
		for (int i = 0; i < surroundingPoints.length; i++)
		{
			int xOffset = (i % 5) - 2; // -2, -1, 0, or 1, 2
			int yOffset = (i / 5) - 2; // -2, -1, 0, or 1, 2
			surroundingPoints[i] = new WorldPoint(newDestination.getX() + xOffset, newDestination.getY() + yOffset, newDestination.getPlane());
		}
		destination = newDestination;
	}

	public boolean getIsFound()
	{
		return isFound;
	}

	public void showOverlay()
	{
		ticksRemaining = config.ticksToDisplay()+2;
		showOverlayImage = true;
	}

	public void hideOverlay()
	{
		showOverlayImage = false;
	}

	public boolean isOverlayVisible()
	{
		return showOverlayImage;
	}

	public void changeOverlayImage(BufferedImage newImg)
	{
		overlay.setOverlayImage(newImg);
	}


	@Provides
	GielinorTravelsConfig provideConfig(ConfigManager configManager)
	{
		return configManager.getConfig(GielinorTravelsConfig.class);
	}
}

