				meadowNorth = gameObject;
				break;
			case MEADOW_SOUTH:
				meadowSouth = gameObject;
				break;
			case VALLEY_NORTH:
				valleyNorth = gameObject;
				break;
			case VALLEY_SOUTH:
				valleySouth = gameObject;
				break;
