				break;
			case MEADOW_SOUTH:
				meadowSouth = null;
				break;
			case VALLEY_NORTH:
				valleyNorth = null;
				break;
			case VALLEY_SOUTH:
				valleySouth = null;
				break;

		}
	}

	@Subscribe
	public void onGameStateChanged(GameStateChanged event)
	{
		if (event.getGameState() == GameState.LOADING)
		{
			meadowNorth = null;
			meadowSouth = null;
			valleyNorth = null;
			valleySouth = null;
		}
