                        // Check if this channel accepts pets (default to true for backward compat)
                        boolean sendPets = !ch.has("sendPets") || ch.get("sendPets").getAsBoolean();

                        if (!sendPets)
                        {
                            log.debug("Channel excluded from pet drops (sendPets=false)");
                            continue;
