                    }
                }
                // Fallback: legacy channelIds format (send to all)
                else if (rawDest.has("channelIds") && rawDest.get("channelIds").isJsonArray())
                {
                    formattedDest.add("channel_ids", rawDest.get("channelIds").getAsJsonArray());
                }
