	@Override
	public void keyReleased(KeyEvent e)
	{
		if (config.cameraRotateRemap() && cameraRotateKeyPressed && config.cameraRotateKey().matches(e))
		{
			cameraRotateKeyPressed = false;
			e.consume();
		}
	}

	@Override
