package com.easytasks.overlays;

import com.easytasks.BirdhouseConfig;
import com.easytasks.tasks.TaskManager;
import com.easytasks.tasks.TaskStep;
import com.easytasks.tasks.birdhouse.BirdhouseData;
import com.easytasks.tasks.birdhouse.BirdhouseLocation;
import com.easytasks.tasks.birdhouse.BirdhouseTask;
import net.runelite.api.Client;
import net.runelite.api.Perspective;
import net.runelite.api.TileObject;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.OverlayUtil;

import javax.inject.Inject;
import java.awt.*;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

public class TeleportHighlightOverlay extends Overlay
{
	private final Client client;
	private final BirdhouseConfig config;
	private final TaskManager taskManager;

	@Inject
	public TeleportHighlightOverlay(Client client, BirdhouseConfig config, TaskManager taskManager)
	{
		this.client = client;
		this.config = config;
		this.taskManager = taskManager;
		setPosition(OverlayPosition.DYNAMIC);
		setLayer(OverlayLayer.ABOVE_SCENE);
	}

	@Override
	public Dimension render(Graphics2D graphics)
	{
		if (!config.highlightTeleports()) return null;
		if (!BirdhouseData.isOnFossilIsland(client)) return null;
		Optional<BirdhouseTask> opt = taskManager.getTaskByType(BirdhouseTask.class);
		if (opt.isEmpty()) return null;
		BirdhouseTask task = opt.get();
		if (!task.isActive()) return null;
		TaskStep step = task.getCurrentStep();
		if (step == null) return null;
		List<Integer> teleportIds = getTeleportIdsForNextStep(task, step);
		if (teleportIds.isEmpty()) return null;
		Color color = config.teleportColor();
		net.runelite.api.Scene scene = client.getScene();
		int plane = client.getPlane();
		for (int x = 0; x < 104; x++)
		{
			for (int y = 0; y < 104; y++)
			{
				net.runelite.api.Tile tile = scene.getTiles()[plane][x][y];
				if (tile == null) continue;
				for (TileObject obj : tile.getGameObjects())
				{
					if (obj == null) continue;
					if (!teleportIds.contains(obj.getId())) continue;
					Shape hull = obj.getClickbox();
					if (hull == null)
					{
						LocalPoint lp = obj.getLocalLocation();
						hull = Perspective.getCanvasTilePoly(client, lp);
					}
					if (hull != null)
					{
						OverlayUtil.renderPolygon(graphics, hull, color, new BasicStroke(config.highlightThickness()));
						return null;
					}
				}
			}
		}
		return null;
	}

	private List<Integer> getTeleportIdsForNextStep(BirdhouseTask task, TaskStep step)
	{
		WorldPoint targetWp = step.getLocation();
		List<BirdhouseLocation> ordered = task.getLocationsInRouteOrder();
		int targetIndex = -1;
		BirdhouseLocation targetLoc = null;
		for (int i = 0; i < ordered.size(); i++)
		{
			if (ordered.get(i).getWorldPoint().equals(targetWp))
			{
				targetIndex = i;
				targetLoc = ordered.get(i);
				break;
			}
		}
		if (targetLoc == null) return List.of();
		List<Integer> ids = new ArrayList<>(targetLoc.getTeleportObjectIds());
		// Only highlight mushroom tree when moving between (Tar Swamp or Forest) and (Verdant Valley N/S)
		BirdhouseLocation fromLoc = targetIndex > 0 ? ordered.get(targetIndex - 1) : null;
		if (fromLoc != null && isMushroomTreeNeeded(fromLoc, targetLoc))
			ids.add(BirdhouseData.MUSHROOM_TREE_TO_VALLEY_OBJECT_ID);
		return ids;
	}

	private static boolean isMushroomTreeNeeded(BirdhouseLocation from, BirdhouseLocation to)
	{
		boolean fromValley = isVerdantValley(from.getWorldPoint());
		boolean toValley = isVerdantValley(to.getWorldPoint());
		boolean fromForestOrSwamp = isMushroomForestOrTarSwamp(from.getWorldPoint());
		boolean toForestOrSwamp = isMushroomForestOrTarSwamp(to.getWorldPoint());
		return (fromValley && toForestOrSwamp) || (fromForestOrSwamp && toValley);
	}

	private static boolean isVerdantValley(WorldPoint wp)
	{
		return wp.equals(BirdhouseData.VERDANT_VALLEY_NORTH) || wp.equals(BirdhouseData.VERDANT_VALLEY_SOUTH);
	}

	private static boolean isMushroomForestOrTarSwamp(WorldPoint wp)
	{
		return wp.equals(BirdhouseData.MUSHROOM_FOREST) || wp.equals(BirdhouseData.TAR_SWAMP);
	}
}

package com.easytasks.overlays;

import com.easytasks.BirdhouseConfig;
import com.easytasks.tasks.TaskManager;
import com.easytasks.tasks.TaskStep;
import com.easytasks.tasks.birdhouse.BirdhouseTask;
import net.runelite.api.Client;
import net.runelite.api.coords.WorldPoint;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.components.LineComponent;
import net.runelite.client.ui.overlay.components.PanelComponent;

import javax.inject.Inject;
import java.awt.Dimension;
import java.awt.Graphics2D;
import java.util.Optional;

/**
 * Text overlay showing current step guidance on screen (like farming-helper's EasyFarmingOverlayInfoBox).
 */
public class StepGuidanceOverlay extends Overlay
{
	private final Client client;
	private final BirdhouseConfig config;
	private final TaskManager taskManager;
	private final PanelComponent panelComponent = new PanelComponent();

	@Inject
	public StepGuidanceOverlay(Client client, BirdhouseConfig config, TaskManager taskManager)
	{
		this.client = client;
		this.config = config;
		this.taskManager = taskManager;
		setPosition(OverlayPosition.TOP_LEFT);
		setLayer(OverlayLayer.ABOVE_WIDGETS);
	}

	@Override
	public Dimension render(Graphics2D graphics)
	{
		if (!config.showStepGuidance()) return null;
		Optional<BirdhouseTask> opt = taskManager.getTaskByType(BirdhouseTask.class);
		if (opt.isEmpty() || !opt.get().isActive()) return null;

		BirdhouseTask task = opt.get();
		TaskStep step = task.getCurrentStep();
		if (step == null) return null;

		panelComponent.getChildren().clear();
		WorldPoint playerWp = client.getLocalPlayer() != null ? client.getLocalPlayer().getWorldLocation() : null;
		int current = task.getCompletedSteps() + 1;
		int total = task.getTotalSteps();
		String instruction = task.getCurrentStepInstruction(playerWp);
		if (instruction == null) instruction = step.getDescription();
		String text = current + "/" + total + ": " + instruction;
		panelComponent.getChildren().add(LineComponent.builder().left(text).build());
		return panelComponent.render(graphics);
	}
}

package com.easytasks.overlays;

import com.easytasks.BirdhouseConfig;
import com.easytasks.tasks.TaskManager;
import com.easytasks.tasks.birdhouse.BirdhouseData;
import com.easytasks.tasks.birdhouse.BirdhouseTask;
import net.runelite.api.widgets.WidgetItem;
import net.runelite.client.game.ItemManager;
import net.runelite.client.ui.overlay.WidgetItemOverlay;

import javax.inject.Inject;
import java.awt.*;
import java.awt.image.BufferedImage;

public class SeedHighlightOverlay extends WidgetItemOverlay
{
	private final BirdhouseConfig config;
	private final TaskManager taskManager;
	private final ItemManager itemManager;

	private static final Color USE_ON_BIRDHOUSE_COLOR = Color.PINK;

	@Inject
	public SeedHighlightOverlay(BirdhouseConfig config, TaskManager taskManager, ItemManager itemManager)
	{
		this.config = config;
		this.taskManager = taskManager;
		this.itemManager = itemManager;
		showOnInventory();
	}

	@Override
	public void renderItemOverlay(Graphics2D graphics, int itemId, WidgetItem widgetItem)
	{
		if (!config.highlightBirdhouses()) return;
		var opt = taskManager.getTaskByType(BirdhouseTask.class);
		if (opt.isEmpty()) return;
		BirdhouseTask task = opt.get();
		if (!task.isActive() || !task.isCurrentStepFillWithSeeds()) return;
		// Highlight any valid birdhouse seed (all 6 types), not just the configured seed
		if (!BirdhouseData.SEED_IDS.contains(itemId)) return;
		Rectangle bounds = widgetItem.getCanvasBounds();
		BufferedImage outline = itemManager.getItemOutline(itemId, widgetItem.getQuantity(), USE_ON_BIRDHOUSE_COLOR);
		if (outline != null)
			graphics.drawImage(outline, (int) bounds.getX(), (int) bounds.getY(), null);
		else
		{
			graphics.setColor(USE_ON_BIRDHOUSE_COLOR);
			graphics.setStroke(new BasicStroke(2));
			graphics.drawRect(bounds.x, bounds.y, bounds.width, bounds.height);
		}
	}
}

package com.easytasks.overlays;

import com.easytasks.BirdhouseConfig;
import com.easytasks.tasks.TaskManager;
import com.easytasks.tasks.birdhouse.BirdhouseData;
import com.easytasks.tasks.birdhouse.BirdhouseLocation;
import com.easytasks.tasks.birdhouse.BirdhouseTask;
import net.runelite.api.Client;
import net.runelite.api.Perspective;
import net.runelite.api.TileObject;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.OverlayUtil;

import javax.inject.Inject;
import java.awt.*;
import java.util.Optional;

public class BirdhouseHighlightOverlay extends Overlay
{
	private final Client client;
	private final BirdhouseConfig config;
	private final TaskManager taskManager;

	@Inject
	public BirdhouseHighlightOverlay(Client client, BirdhouseConfig config, TaskManager taskManager)
	{
		this.client = client;
		this.config = config;
		this.taskManager = taskManager;
		setPosition(OverlayPosition.DYNAMIC);
		setLayer(OverlayLayer.ABOVE_SCENE);
	}

	@Override
	public Dimension render(Graphics2D graphics)
	{
		if (!config.highlightBirdhouses()) return null;
		if (!BirdhouseData.isOnFossilIsland(client)) return null;
		Optional<BirdhouseTask> opt = taskManager.getTaskByType(BirdhouseTask.class);
		if (opt.isEmpty()) return null;
		BirdhouseTask task = opt.get();
		if (!task.isActive()) return null;
		net.runelite.api.Scene scene = client.getScene();
		int plane = client.getPlane();
		BirdhouseLocation currentStepLoc = task.getCurrentStepLocation();
		boolean fillWithSeeds = task.isCurrentStepFillWithSeeds();
		for (BirdhouseLocation loc : task.getLocationsInRouteOrder())
		{
			if (loc.isVisited()) continue;
			Color color;
			if (fillWithSeeds && loc == currentStepLoc)
				color = Color.PINK;
			else if (loc.isEmpty(client)) color = config.emptySlotColor();
			else if (loc.isPlaced(client)) color = config.emptyBirdhouseColor();
			else if (loc.isOccupied(client)) color = config.occupiedBirdhouseColor();
			else color = config.emptySlotColor();
			WorldPoint wp = loc.getWorldPoint();
			LocalPoint localPoint = LocalPoint.fromWorld(client, wp);
			if (localPoint == null) continue;
			Shape hull = null;
			net.runelite.api.Tile tile = scene.getTiles()[plane][localPoint.getSceneX()][localPoint.getSceneY()];
			if (tile != null)
			{
				for (TileObject obj : tile.getGameObjects())
				{
					if (obj == null) continue;
					Shape box = obj.getClickbox();
					if (box != null)
					{
						hull = box;
						break;
					}
				}
			}
			if (hull == null)
				hull = Perspective.getCanvasTilePoly(client, localPoint);
			if (hull != null)
				OverlayUtil.renderPolygon(graphics, hull, color, new BasicStroke(config.highlightThickness()));
		}
		return null;
	}
}

package com.easytasks;

import com.easytasks.tasks.Task;
import com.easytasks.tasks.TaskManager;
import com.easytasks.tasks.birdhouse.BirdhouseTask;
import com.easytasks.ui.BirdhouseSidePanel;
import com.easytasks.overlays.BirdhouseHighlightOverlay;
import com.easytasks.overlays.SeedHighlightOverlay;
import com.easytasks.overlays.StepGuidanceOverlay;
import com.easytasks.overlays.TeleportHighlightOverlay;
import com.google.inject.Provides;
import javax.inject.Provider;
import com.easytasks.tasks.birdhouse.BirdhouseMode;
import net.runelite.api.ChatMessageType;
import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.api.events.GameStateChanged;
import net.runelite.api.events.GameTick;
import net.runelite.api.events.ItemContainerChanged;
import net.runelite.api.events.MenuOptionClicked;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.Subscribe;
import net.runelite.client.events.ConfigChanged;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.ui.ClientToolbar;
import net.runelite.client.ui.NavigationButton;
import net.runelite.client.game.ItemManager;
import net.runelite.client.ui.overlay.OverlayManager;
import net.runelite.client.ui.overlay.infobox.InfoBoxManager;
import net.runelite.client.util.ImageUtil;

import javax.inject.Inject;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.util.ArrayList;
import java.util.List;
import lombok.extern.slf4j.Slf4j;

@Slf4j
@PluginDescriptor(
	name = "Easy Tasks",
	description = "Assists with birdhouse runs on Fossil Island",
	tags = {"birdhouse", "hunter", "fossil island", "skilling"}
)
public class BirdhousePlugin extends Plugin implements TaskManager.TaskStateListener
{
	@Inject
	private Client client;

	@Inject
	private ClientThread clientThread;

	@Inject
	private BirdhouseConfig config;

	@Inject
	private TaskManager taskManager;

	@Inject
	private OverlayManager overlayManager;

	@Inject
	private BirdhouseHighlightOverlay birdhouseHighlightOverlay;

	@Inject
	private SeedHighlightOverlay seedHighlightOverlay;

	@Inject
	private TeleportHighlightOverlay teleportHighlightOverlay;

	@Inject
	private StepGuidanceOverlay stepGuidanceOverlay;

	@Inject
	private ItemManager itemManager;

	@Inject
	private ClientToolbar clientToolbar;

	@Inject
	private BirdhouseSidePanel sidePanel;

	@Inject
	private Provider<BirdhouseTask> birdhouseTaskProvider;

	@Inject
	private InfoBoxManager infoBoxManager;

	private NavigationButton navButton;
	private List<com.easytasks.infoboxes.ItemTrackingInfoBox> itemTrackingInfoBoxes = new ArrayList<>();

	@Provides
	BirdhouseConfig provideConfig(ConfigManager configManager)
	{
		return configManager.getConfig(BirdhouseConfig.class);
	}

	@Override
	protected void startUp() throws Exception
	{
		overlayManager.add(birdhouseHighlightOverlay);
		overlayManager.add(seedHighlightOverlay);
		overlayManager.add(teleportHighlightOverlay);
		overlayManager.add(stepGuidanceOverlay);
		BufferedImage icon = createNavIcon();
		navButton = NavigationButton.builder()
			.icon(icon)
			.panel(sidePanel)
			.tooltip("Easy Tasks")
			.build();
		clientToolbar.addNavigation(navButton);

		sidePanel.setOnStartRequested(this::startBirdhouseRun);
		sidePanel.setOnStopRequested(this::stopBirdhouseRun);
		sidePanel.setOnItemListRefreshRequested(this::refreshItemTrackingInfoBox);
		taskManager.addTaskStateListener(this);

		log.debug("Easy Tasks started!");
	}

	@Override
	protected void shutDown() throws Exception
	{
		taskManager.removeTaskStateListener(this);
		stopBirdhouseRun();
		removeBirdhouseInfoBoxes();
		clientToolbar.removeNavigation(navButton);
		overlayManager.remove(stepGuidanceOverlay);
		overlayManager.remove(teleportHighlightOverlay);
		overlayManager.remove(seedHighlightOverlay);
		overlayManager.remove(birdhouseHighlightOverlay);
		log.debug("Easy Tasks stopped!");
	}

	private void startBirdhouseRun()
	{
		int[] routeOrder = sidePanel.getRouteOrder();
		BirdhouseMode mode = config.birdhouseMode();
		clientThread.invokeLater(() -> {
			BirdhouseTask task = birdhouseTaskProvider.get();
			task.setRouteOrder(routeOrder);
			task.setMode(mode);
			task.setOnCompleteCallback(this::onTaskComplete);
			taskManager.registerTask(task);

			removeBirdhouseInfoBoxes();
			if (config.showItemTracking())
			{
				itemTrackingInfoBoxes = new ArrayList<>();
				for (Task.RequiredItem ri : task.getRequiredItems())
				{
					BufferedImage itemBoxImage = itemManager.getImage(ri.getItemId());
					if (itemBoxImage == null) itemBoxImage = createNavIcon();
					com.easytasks.infoboxes.ItemTrackingInfoBox box = new com.easytasks.infoboxes.ItemTrackingInfoBox(itemBoxImage, this, ri, task, client, itemManager);
					infoBoxManager.addInfoBox(box);
					itemTrackingInfoBoxes.add(box);
				}
			}
			else
				itemTrackingInfoBoxes = new ArrayList<>();
		});
	}

	private void stopBirdhouseRun()
	{
		taskManager.getTaskByType(BirdhouseTask.class).ifPresent(task -> {
			taskManager.unregisterTask(task);
			clientThread.invokeLater(() ->
				client.addChatMessage(ChatMessageType.GAMEMESSAGE, "", "Easy Tasks: Run stopped.", null));
		});
	}

	/** Called when the final location completes; stops the run (unregisters task). */
	private void onTaskComplete()
	{
		taskManager.getTaskByType(BirdhouseTask.class).ifPresent(task -> {
			taskManager.unregisterTask(task);
		});
		// Ensure side panel button and progress reset to "Start Birdhouse Run".
		sidePanel.setRunIdle();
	}

	private void applyConfigToTask(BirdhouseTask task)
	{
		task.setMode(config.birdhouseMode());
		task.setRouteOrder(sidePanel.getRouteOrder());
	}

	private void refreshItemTrackingInfoBox()
	{
		for (com.easytasks.infoboxes.ItemTrackingInfoBox box : itemTrackingInfoBoxes)
			box.update();
	}

	private void removeBirdhouseInfoBoxes()
	{
		for (com.easytasks.infoboxes.ItemTrackingInfoBox box : itemTrackingInfoBoxes)
			infoBoxManager.removeInfoBox(box);
		itemTrackingInfoBoxes.clear();
	}

	private static BufferedImage createNavIcon()
	{
		BufferedImage img = new BufferedImage(24, 24, BufferedImage.TYPE_INT_ARGB);
		Graphics2D g = img.createGraphics();
		g.setColor(new Color(70, 130, 180));
		g.fillRoundRect(0, 0, 24, 24, 4, 4);
		g.setColor(Color.WHITE);
		g.setFont(new Font("SansSerif", Font.BOLD, 12));
		g.drawString("ET", 4, 17);
		g.dispose();
		return ImageUtil.resizeImage(img, 24, 24);
	}

	@Subscribe
	public void onGameStateChanged(GameStateChanged event)
	{
		if (event.getGameState() == GameState.LOGIN_SCREEN)
		{
			stopBirdhouseRun();
		}
	}

	@Subscribe
	public void onGameTick(GameTick event)
	{
		taskManager.getTaskByType(BirdhouseTask.class).ifPresent(BirdhouseTask::checkProximityAndAdvance);
	}

	@Subscribe
	public void onMenuOptionClicked(MenuOptionClicked event)
	{
		taskManager.getTaskByType(BirdhouseTask.class).ifPresent(task ->
			task.onMenuOptionClicked(event.getMenuOption(), event.getId(), event.getParam0(), event.getParam1()));
	}

	@Subscribe
	public void onItemContainerChanged(ItemContainerChanged event)
	{
		if (event.getContainerId() != net.runelite.api.InventoryID.INVENTORY.getId())
			return;
		for (com.easytasks.infoboxes.ItemTrackingInfoBox box : itemTrackingInfoBoxes)
			box.update();
	}

	@Subscribe
	public void onConfigChanged(ConfigChanged event)
	{
		if (!"birdhouse".equals(event.getGroup())) return;
		sidePanel.refreshFromConfig();
		taskManager.getTaskByType(BirdhouseTask.class).ifPresent(this::applyConfigToTask);
		sidePanel.refreshItemList();
	}

	@Override
	public void onTaskStateChanged(Task task)
	{
		// Step guidance is shown only via StepGuidanceOverlay, not as an infobox.
	}
}

package com.easytasks.ui;

import com.easytasks.BirdhouseConfig;
import com.easytasks.tasks.Task;
import com.easytasks.tasks.TaskManager;
import com.easytasks.tasks.birdhouse.BirdhouseTask;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.ui.PluginPanel;

import javax.inject.Inject;
import javax.swing.*;
import java.awt.*;
import java.awt.datatransfer.DataFlavor;
import java.awt.datatransfer.StringSelection;
import java.awt.datatransfer.Transferable;
import java.util.Optional;

public class BirdhouseSidePanel extends PluginPanel implements TaskManager.TaskStateListener
{
	private static final String[] LOCATION_NAMES = {"Verdant Valley (North)", "Verdant Valley (South)", "Mushroom Forest", "Tar Swamp"};

	private static final Color BG_DARK = new Color(0x2b2b2b);
	private static final Color BG_PANEL = new Color(0x1e1e1e);
	private static final Color FG_LIGHT = new Color(0xe0e0e0);
	private static final Color BUTTON_BG = new Color(0x1a1a1a);
	private static final Color BUTTON_FG = Color.WHITE;
	private static final Color PROGRESS_BG = new Color(0x333333);
	private static final Color PROGRESS_FG = new Color(0x4a9eff);

	private final BirdhouseConfig config;
	private final TaskManager taskManager;
	private final ConfigManager configManager;

	private final JButton startStopButton;
	private final JProgressBar progressBar;
	private final JLabel progressLabel;
	private final JList<Integer> routeList;
	private final DefaultListModel<Integer> routeModel;

	private Runnable onStartRequested;
	private Runnable onStopRequested;
	private Runnable onItemListRefreshRequested;

	@Inject
	public BirdhouseSidePanel(BirdhouseConfig config, TaskManager taskManager, ConfigManager configManager)
	{
		this.config = config;
		this.taskManager = taskManager;
		this.configManager = configManager;

		setLayout(new BorderLayout(0, 8));
		setBorder(BorderFactory.createEmptyBorder(10, 10, 10, 10));
		setBackground(BG_DARK);

		JPanel header = new JPanel(new FlowLayout(FlowLayout.LEFT, 0, 0));
		header.setBackground(BG_DARK);
		JLabel title = new JLabel("Pick a birdhouse run:");
		title.setFont(title.getFont().deriveFont(Font.PLAIN, 13f));
		title.setForeground(FG_LIGHT);
		header.add(title);
		add(header, BorderLayout.NORTH);

		JPanel center = new JPanel();
		center.setLayout(new BoxLayout(center, BoxLayout.Y_AXIS));
		center.setBackground(BG_DARK);

		startStopButton = new JButton("Start Birdhouse Run");
		startStopButton.addActionListener(e -> toggleRun());
		styleButton(startStopButton);
		center.add(startStopButton);
		center.add(Box.createVerticalStrut(10));

		progressBar = new JProgressBar(0, 100);
		progressBar.setValue(0);
		progressBar.setPreferredSize(new Dimension(0, 14));
		progressBar.setBackground(PROGRESS_BG);
		progressBar.setForeground(PROGRESS_FG);
		center.add(progressBar);
		progressLabel = new JLabel("0/4 locations completed");
		progressLabel.setForeground(FG_LIGHT);
		progressLabel.setAlignmentX(Component.LEFT_ALIGNMENT);
		center.add(progressLabel);
		center.add(Box.createVerticalStrut(12));

		JLabel routeTitle = new JLabel("Route order (drag to reorder)");
		routeTitle.setForeground(FG_LIGHT);
		routeTitle.setAlignmentX(Component.LEFT_ALIGNMENT);
		center.add(routeTitle);
		center.add(Box.createVerticalStrut(4));
		routeModel = new DefaultListModel<>();
		routeList = new JList<>(routeModel);
		routeList.setSelectionMode(ListSelectionModel.SINGLE_SELECTION);
		routeList.setDragEnabled(true);
		routeList.setDropMode(DropMode.INSERT);
		routeList.setTransferHandler(new RouteOrderTransferHandler());
		routeList.setBackground(BG_PANEL);
		routeList.setForeground(FG_LIGHT);
		routeList.setSelectionBackground(new Color(0x404040));
		routeList.setSelectionForeground(FG_LIGHT);
		routeList.setCellRenderer((list, value, index, isSelected, cellHasFocus) -> {
			String display = getRouteDisplayName(value);
			JLabel l = new JLabel((index + 1) + ". " + display);
			l.setOpaque(true);
			l.setBackground(isSelected ? list.getSelectionBackground() : BG_PANEL);
			l.setForeground(isSelected ? list.getSelectionForeground() : FG_LIGHT);
			return l;
		});
		routeList.setVisibleRowCount(4);
		routeList.setPreferredSize(new Dimension(0, 80));
		JScrollPane routeScroll = new JScrollPane(routeList);
		routeScroll.setVerticalScrollBarPolicy(ScrollPaneConstants.VERTICAL_SCROLLBAR_NEVER);
		routeScroll.setBackground(BG_DARK);
		routeScroll.getViewport().setBackground(BG_PANEL);
		center.add(routeScroll);

		JScrollPane scroll = new JScrollPane(center);
		scroll.setHorizontalScrollBarPolicy(ScrollPaneConstants.HORIZONTAL_SCROLLBAR_NEVER);
		scroll.setBorder(BorderFactory.createEmptyBorder(0, 0, 0, 0));
		scroll.getViewport().setBackground(BG_DARK);
		add(scroll, BorderLayout.CENTER);
	}

	@Override
	public void addNotify()
	{
		super.addNotify();
		taskManager.addTaskStateListener(this);
		refreshRouteOrderFromConfig();
	}

	@Override
	public void removeNotify()
	{
		taskManager.removeTaskStateListener(this);
		super.removeNotify();
	}

	private static void styleButton(JButton btn)
	{
		btn.setBackground(BUTTON_BG);
		btn.setForeground(BUTTON_FG);
		btn.setFocusPainted(false);
		btn.setBorder(BorderFactory.createLineBorder(new Color(0x444444)));
		btn.setPreferredSize(new Dimension(0, 28));
		btn.setMaximumSize(new Dimension(Integer.MAX_VALUE, 28));
	}

	@SuppressWarnings("boxing")
	private static String getRouteDisplayName(Object value)
	{
		if (value == null || !(value instanceof Integer))
			return value == null ? "Unknown" : String.valueOf(value);
		int idx = (Integer) value;
		if (idx < 0 || idx >= LOCATION_NAMES.length)
			return "Unknown";
		return LOCATION_NAMES[idx];
	}

	private void toggleRun()
	{
		Optional<BirdhouseTask> existing = taskManager.getTaskByType(BirdhouseTask.class);
		if (existing.isPresent())
		{
			if (onStopRequested != null) onStopRequested.run();
		}
		else
		{
			if (onStartRequested != null) onStartRequested.run();
		}
	}

	public void setOnStartRequested(Runnable r) { onStartRequested = r; }
	public void setOnStopRequested(Runnable r) { onStopRequested = r; }
	public void setOnItemListRefreshRequested(Runnable r) { onItemListRefreshRequested = r; }

	/** Refreshes the item checklist (e.g. required-items infobox). Called when config changes. */
	public void refreshItemList()
	{
		if (onItemListRefreshRequested != null)
			onItemListRefreshRequested.run();
	}

	@Override
	public void onTaskRegistered(Task task)
	{
		SwingUtilities.invokeLater(() -> updateForTask(task));
	}

	@Override
	public void onTaskUnregistered(Task task)
	{
		SwingUtilities.invokeLater(this::updateIdle);
	}

	@Override
	public void onTaskStateChanged(Task task)
	{
		SwingUtilities.invokeLater(() -> updateForTask(task));
	}

	private void updateForTask(Task task)
	{
		if (!(task instanceof BirdhouseTask)) return;
		BirdhouseTask bt = (BirdhouseTask) task;
		startStopButton.setText("Stop Birdhouse Run");
		progressBar.setValue(bt.getProgress());
		progressLabel.setText(bt.getCompletedSteps() + "/" + bt.getTotalSteps() + " locations completed");
	}

	private void updateIdle()
	{
		startStopButton.setText("Start Birdhouse Run");
		progressBar.setValue(0);
		progressLabel.setText("0/4 locations completed");
	}

	/** Called when the run completes or stops so the button and progress reset. Safe to call from any thread. */
	public void setRunIdle()
	{
		SwingUtilities.invokeLater(this::updateIdle);
	}

	private void refreshRouteOrderFromConfig()
	{
		routeModel.clear();
		String order = configManager.getConfiguration("birdhouse", "routeOrder");
		if (order == null || order.isBlank()) order = "0,1,2,3";
		java.util.Set<Integer> added = new java.util.HashSet<>();
		for (String idxStr : order.split(","))
		{
			try
			{
				int i = Integer.parseInt(idxStr.trim());
				if (i >= 0 && i < 4 && added.add(i)) routeModel.addElement(i);
			}
			catch (NumberFormatException ignored) {}
		}
		for (int i = 0; i < 4; i++)
			if (!added.contains(i)) routeModel.addElement(i);
	}

	private void persistRouteOrder()
	{
		StringBuilder sb = new StringBuilder();
		for (int i = 0; i < routeModel.getSize(); i++)
		{
			if (i > 0) sb.append(",");
			sb.append(routeModel.get(i));
		}
		configManager.setConfiguration("birdhouse", "routeOrder", sb.toString());
	}

	/** Plan §4.1: Drag-and-drop reorder; persists routeOrder config immediately. */
	private class RouteOrderTransferHandler extends TransferHandler
	{
		private int sourceIndex = -1;

		@Override
		protected Transferable createTransferable(JComponent c)
		{
			if (!(c instanceof JList)) return null;
			@SuppressWarnings("unchecked")
			JList<Integer> list = (JList<Integer>) c;
			sourceIndex = list.getSelectedIndex();
			if (sourceIndex < 0 || sourceIndex >= routeModel.getSize()) return null;
			return new StringSelection(sourceIndex + ":" + routeModel.get(sourceIndex));
		}

		@Override
		public int getSourceActions(JComponent c) { return MOVE; }

		@Override
		public boolean canImport(TransferHandler.TransferSupport support)
		{
			if (!support.isDrop() || !support.isDataFlavorSupported(DataFlavor.stringFlavor)) return false;
			JList.DropLocation dl = (JList.DropLocation) support.getDropLocation();
			return dl.getIndex() >= 0 && dl.getIndex() <= routeModel.getSize();
		}

		@Override
		public boolean importData(TransferHandler.TransferSupport support)
		{
			if (!canImport(support)) return false;
			try
			{
				String data = (String) support.getTransferable().getTransferData(DataFlavor.stringFlavor);
				String[] parts = data.split(":");
				if (parts.length != 2) return false;
				int from = Integer.parseInt(parts[0]);
				int value = Integer.parseInt(parts[1]);
				int dropIndex = ((JList.DropLocation) support.getDropLocation()).getIndex();
				if (from == dropIndex || from == dropIndex - 1) return true;
				routeModel.remove(from);
				int insert = dropIndex > from ? dropIndex - 1 : dropIndex;
				routeModel.add(insert, value);
				persistRouteOrder();
				return true;
			}
			catch (Exception e) { return false; }
		}

		@Override
		protected void exportDone(JComponent source, Transferable data, int action)
		{
			sourceIndex = -1;
		}
	}

	public void refreshFromConfig() { SwingUtilities.invokeLater(this::refreshRouteOrderFromConfig); }

	/** Returns current route order (indices 0–3) for the task. Used when starting a run. */
	public int[] getRouteOrder()
	{
		int n = routeModel.getSize();
		int[] order = new int[4];
		for (int i = 0; i < 4 && i < n; i++)
			order[i] = routeModel.get(i);
		for (int i = n; i < 4; i++)
			order[i] = i;
		return order;
	}
}

package com.easytasks.infoboxes;

import com.easytasks.tasks.Task;
import net.runelite.api.Client;
import net.runelite.api.InventoryID;
import net.runelite.api.Item;
import net.runelite.api.ItemContainer;
import net.runelite.client.game.ItemManager;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.ui.overlay.infobox.InfoBox;

import java.awt.Color;
import java.awt.image.BufferedImage;
import java.util.List;

/**
 * Tracks a single required item and auto-removes when gathered.
 * Multiple instances are created per task, one for each required item.
 * If the user drops items mid-run after gathering, infoboxes will reappear
 * (missing count updates from inventory); this is intentional.
 */
public class ItemTrackingInfoBox extends InfoBox
{
	private final Task task;
	private final Task.RequiredItem requiredItem;
	private final Client client;
	private final ItemManager itemManager;
	private int missingCount = 0;
	private String tooltipText = "";

	public ItemTrackingInfoBox(BufferedImage image, Plugin plugin, Task.RequiredItem requiredItem, Task task, Client client, ItemManager itemManager)
	{
		super(image, plugin);
		this.requiredItem = requiredItem;
		this.task = task;
		this.client = client;
		this.itemManager = itemManager;
		update();
	}

	/** Only the count still needed is shown on the infobox; no other text. */
	@Override
	public String getText()
	{
		if (missingCount > 0)
			return missingCount + "x";
		return "";
	}

	@Override
	public Color getTextColor()
	{
		return missingCount <= 0 ? Color.GREEN : Color.ORANGE;
	}

	@Override
	public boolean render()
	{
		return missingCount > 0 && task.isActive();
	}

	@Override
	public String getTooltip()
	{
		return tooltipText;
	}

	/** Called when inventory changes; recomputes missing count and tooltip for this item. */
	public void update()
	{
		if (task == null || !task.isActive())
		{
			missingCount = 0;
			tooltipText = "";
			return;
		}
		ItemContainer inv = client.getItemContainer(InventoryID.INVENTORY);
		int have = countItemsInList(inv, requiredItem.getItemIds());
		missingCount = Math.max(0, requiredItem.getQuantity() - have);
		String itemName = itemManager.getItemComposition(requiredItem.getItemId()).getName();
		if (missingCount > 0)
			tooltipText = "Need " + missingCount + " more " + itemName;
		else
			tooltipText = itemName + ": Ready";
		setTooltip(tooltipText);
	}

	private static int countItemsInList(ItemContainer container, List<Integer> itemIds)
	{
		if (container == null || itemIds == null) return 0;
		int count = 0;
		for (Item item : container.getItems())
			if (itemIds.contains(item.getId())) count += item.getQuantity();
		return count;
	}
}

