@Data
@NoArgsConstructor
@EqualsAndHashCode(of = {"countSincePersonal", "lastPersonalItem", "countSinceOther"})
public class LootTrackingMemory
{
    int countSincePersonal;
    String lastPersonalItem;
    int countSinceOther;

    public LootTrackingMemory(int countSincePersonal, String lastPersonalItem, int countSinceOther)
    {
        this.countSincePersonal = countSincePersonal;
        this.lastPersonalItem = lastPersonalItem;
        this.countSinceOther = countSinceOther;
    }
}

