	@Getter
	private List<GroundObject> exerciseMatsAnswerList;

	// <Post Number, Mat>
	private Multimap<Integer, GroundObject> exerciseMatsMultimap;

	// <Exercise Varbit, Mat>
	private Multimap<Integer, GroundObject> exerciseVarbitMatMultimap;

	@Getter
