package com.divinedialogue;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Random;
import java.util.Set;
import lombok.extern.slf4j.Slf4j;
import net.runelite.client.audio.AudioPlayer;

/**
 * Wrapper around RuneLite's {@link AudioPlayer} for typewriter click playback.
 *
 * <p>Each {@link TypewriterSound} option carries a list of variant sample paths.
 * On every play, we pick one variant at random — this substitutes for the per-play
 * pitch variation we used to do manually, producing the same natural feel without
 * touching {@code javax.sound} APIs directly (banned by the Plugin Hub policy
 * scanner).</p>
 *
 * <p>WAV samples are <em>preloaded into memory</em> on first play and held as
 * {@code byte[]} buffers. On each play, we wrap the bytes in a fresh
 * {@link ByteArrayInputStream} and hand it to {@link AudioPlayer#play(InputStream, float)}.
 * This matters for two reasons:
 * <ul>
 *   <li>The {@code play(Class, String, float)} overload can return "Stream closed"
 *       errors in certain classpath configurations (particularly when resources
 *       live inside a nested jar). Passing our own {@code InputStream} sidesteps
 *       that entire code path.</li>
 *   <li>At ~14 KB per WAV × 8 variants = ~112 KB total, the memory cost is
 *       negligible and we avoid re-reading from disk/jar on every keystroke.</li>
 * </ul>
 *
 * <p>Volume is mapped from the config's 0-100 scale into a dB gain via a
 * logarithmic taper so the slider feels linear to the ear.</p>
 */
@Slf4j
@Singleton
public class SoundPlayer
{
    /** Minimum dB to apply when volume is above zero. Below this, human hearing loses it anyway. */
    private static final float MIN_GAIN_DB = -40f;

    private final AudioPlayer audioPlayer;
    private final Random random = new Random();

    /** Preloaded WAV bytes, keyed by resource path. Populated lazily on first play. */
    private final Map<String, byte[]> audioCache = new HashMap<>();
    /** Paths we've tried and failed to load — skip these instead of retrying forever. */
    private final Set<String> loadFailed = new HashSet<>();

    /** Variants we've already logged a playback failure for — prevents log spam. */
    private final Set<String> pathFailureWarned = new HashSet<>();

    private boolean preloaded = false;

    @Inject
    public SoundPlayer(AudioPlayer audioPlayer)
    {
        this.audioPlayer = audioPlayer;
    }

    /**
     * Plays one randomly-picked variant of the given sound at the specified volume.
     *
     * @param sound  which sound to play; NONE or sounds with no variants are silently ignored
     * @param volume 0–100; 0 is silent (skipped entirely), values are clamped to range
     */
    public void play(TypewriterSound sound, int volume)
    {
        preloadOnce();

        if (sound == null || sound == TypewriterSound.NONE)
        {
            return;
        }
        List<String> variants = sound.getVariantPaths();
        if (variants == null || variants.isEmpty())
        {
            return;
        }
        int clamped = Math.max(0, Math.min(100, volume));
        if (clamped == 0)
        {
            return;
        }

        // Filter to variants that actually loaded successfully.
        List<String> available = new ArrayList<>(variants.size());
        for (String path : variants)
        {
            if (audioCache.containsKey(path))
            {
                available.add(path);
            }
        }
        if (available.isEmpty())
        {
            return;
        }

        String path = available.get(random.nextInt(available.size()));
        byte[] bytes = audioCache.get(path);
        float gain = volumeToGainDb(clamped);

        // Wrap in a fresh ByteArrayInputStream each play — AudioPlayer may close
        // the stream after reading, so it must be re-created per invocation.
        try (InputStream stream = new ByteArrayInputStream(bytes))
        {
            audioPlayer.play(stream, gain);
        }
        catch (Exception e)
        {
            // AudioPlayer.play() declares IOException, UnsupportedAudioFileException,
            // and LineUnavailableException — all from javax.sound.sampled. We catch
            // Exception generically to avoid importing javax.sound.sampled types into
            // plugin code, which is restricted by the Plugin Hub policy scanner.
            if (pathFailureWarned.add(path))
            {
                log.warn("Divine Dialogue: could not play typewriter sound variant {} ({}): {}. "
                    + "Ensure the WAV is 16-bit PCM and your audio drivers are working.",
                    sound, path, e.getMessage());
            }
        }
    }

    /**
     * On first play() call, read every declared variant WAV into an in-memory
     * byte buffer. This pays the I/O cost once at startup and leaves playback
     * as a simple memory-to-mixer copy. Runs exactly once per plugin lifetime.
     */
    private void preloadOnce()
    {
        if (preloaded)
        {
            return;
        }
        preloaded = true;

        List<String> loaded = new ArrayList<>();
        for (TypewriterSound sound : TypewriterSound.values())
        {
            for (String path : sound.getVariantPaths())
            {
                if (audioCache.containsKey(path) || loadFailed.contains(path))
                {
                    continue;
                }
                byte[] bytes = readResource(path);
                if (bytes != null)
                {
                    audioCache.put(path, bytes);
                    loaded.add(path);
                }
                else
                {
                    loadFailed.add(path);
                }
            }
        }
        log.debug("Divine Dialogue: preloaded {} typewriter samples ({}). Failed: {}.",
            loaded.size(), loaded, loadFailed);
    }

    /** Reads a classpath resource into a byte array. Returns null if missing or unreadable. */
    private static byte[] readResource(String path)
    {
        try (InputStream in = SoundPlayer.class.getClassLoader().getResourceAsStream(path))
        {
            if (in == null)
            {
                log.warn("Divine Dialogue: typewriter sound resource missing: {}", path);
                return null;
            }
            ByteArrayOutputStream out = new ByteArrayOutputStream();
            byte[] buf = new byte[8192];
            int n;
            while ((n = in.read(buf)) != -1)
            {
                out.write(buf, 0, n);
            }
            return out.toByteArray();
        }
        catch (IOException e)
        {
            log.warn("Divine Dialogue: failed to read typewriter sound resource {}: {}",
                path, e.getMessage());
            return null;
        }
    }

    /**
     * Maps the config's 0-100 volume slider to a dB gain value.
     * 0 is handled upstream (skip). 100 → 0 dB (no change). Between, a logarithmic
     * taper: 50 → -6 dB (half perceived loudness), 10 → -20 dB, etc.
     * Clamped at {@link #MIN_GAIN_DB} on the low end.
     */
    private static float volumeToGainDb(int volumePct)
    {
        float pct = volumePct / 100f;
        float db = (float) (20.0 * Math.log10(pct));
        if (db < MIN_GAIN_DB)
        {
            db = MIN_GAIN_DB;
        }
        if (db > 0f)
        {
            db = 0f;
        }
        return db;
    }
}

package com.divinedialogue;

/**
 * Font choices exposed in config.
 *
 * <p>A null {@code resourcePath} means "use the platform's built-in font family"
 * (looked up by {@code logicalName}) — no TTF/OTF file needed in resources.</p>
 */
public enum FontChoice
{
    SERIF("Serif", null, "Serif"),
    SANS_SERIF("Sans Serif", "fonts/inter.ttf", "SansSerif"),
    PIXEL("Pixel", "fonts/runescape_uf.ttf", "Monospaced"),
    DYSLEXIC("Dyslexic", "fonts/OpenDyslexic-Regular.otf", "SansSerif");

    private final String displayName;
    private final String resourcePath;
    private final String logicalName;

    FontChoice(String displayName, String resourcePath, String logicalName)
    {
        this.displayName = displayName;
        this.resourcePath = resourcePath;
        this.logicalName = logicalName;
    }

    /** Path inside {@code src/main/resources/}, or null if using a platform font. */
    public String getResourcePath()
    {
        return resourcePath;
    }

    /** Platform logical font family used when no resource is bundled (or as fallback). */
    public String getLogicalName()
    {
        return logicalName;
    }

    @Override
    public String toString()
    {
        return displayName;
    }
}

package com.divinedialogue;

import com.google.inject.Provides;
import java.awt.Font;
import java.awt.GraphicsEnvironment;
import java.awt.Point;
import java.io.InputStream;
import java.util.EnumMap;
import java.util.Map;
import javax.inject.Inject;
import lombok.Getter;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.api.Player;
import net.runelite.api.events.GameStateChanged;
import net.runelite.api.events.GameTick;
import net.runelite.api.widgets.ComponentID;
import net.runelite.api.widgets.Widget;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.Subscribe;
import net.runelite.client.events.ConfigChanged;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.ui.overlay.OverlayManager;

@Slf4j
@PluginDescriptor(
    name = "Divine Dialogue",
    description = "Mirrors NPC and player dialogue into a configurable, styled overlay window.",
    tags = {"dialogue", "npc", "overlay", "accessibility", "content-creation"}
)
public class DivineDialoguePlugin extends Plugin
{
    @Inject private Client client;
    @Inject private OverlayManager overlayManager;
    @Inject private DivineDialogueConfig config;
    @Inject private DivineDialogueOverlay overlay;

    @Getter
    private DialogueState state = DialogueState.IDLE;

    /** The current line the overlay should be rendering, or null when idle. */
    @Getter
    private DialogueLine currentLine;

    /** The text of the last NPC line we displayed, used to detect multi-page dialogue changes. */
    private String lastNpcText = null;
    private String lastNpcName = null;

    /** Pre-loaded fonts keyed by config enum. Populated on startup. */
    private final Map<FontChoice, Font> loadedFonts = new EnumMap<>(FontChoice.class);

    /** Last known overlay location we persisted, used to detect user drags. */
    private Point lastKnownLocation = null;

    /** Plays typewriter sound effects through RuneLite's AudioPlayer. */
    @Inject
    @Getter
    private SoundPlayer soundPlayer;

    @Provides
    DivineDialogueConfig provideConfig(ConfigManager configManager)
    {
        return configManager.getConfig(DivineDialogueConfig.class);
    }

    @Override
    protected void startUp()
    {
        loadFonts();
        overlay.setPlugin(this);
        overlayManager.add(overlay);
        applySavedPosition();
        resetConversation();
        log.debug("Divine Dialogue started");
    }

    @Override
    protected void shutDown()
    {
        overlayManager.remove(overlay);
        resetConversation();
        overlay.invalidateGradientCache();
        log.debug("Divine Dialogue stopped");
    }

    @Subscribe
    public void onConfigChanged(ConfigChanged event)
    {
        if (!DivineDialogueConfig.GROUP.equals(event.getGroup()))
        {
            return;
        }

        // Handle the "reset position" pseudo-button.
        if ("resetPosition".equals(event.getKey()) && config.resetPosition())
        {
            config.resetPosition(false); // auto-untick
            config.positionX(-1);
            config.positionY(-1);
            overlay.setPreferredLocation(null);
        }
        else if ("positionX".equals(event.getKey()) || "positionY".equals(event.getKey()))
        {
            applySavedPosition();
        }

        // Colors/dimensions may have changed; clear the gradient cache.
        overlay.invalidateGradientCache();
    }

    /**
     * Clear the overlay whenever the player leaves the LOGGED_IN state. This catches
     * world hops, logout, login-screen returns, connection drops, and the brief
     * "hopping worlds" screen — situations where {@link #onGameTick} stops firing
     * before the dialogue widgets get a chance to disappear, which would otherwise
     * leave the last line (commonly the "Are you sure you wish to switch to World N?"
     * sprite-text) stuck on screen after the hop completes.
     */
    @Subscribe
    public void onGameStateChanged(GameStateChanged event)
    {
        GameState gs = event.getGameState();
        if (gs != GameState.LOGGED_IN)
        {
            resetConversation();
        }
    }

    /**
     * Read X/Y from config and push to the overlay. A value of -1 means "unset" and
     * leaves the overlay at whatever snap-corner RuneLite chose.
     */
    private void applySavedPosition()
    {
        int x = config.positionX();
        int y = config.positionY();
        if (x < 0 || y < 0)
        {
            overlay.setPreferredLocation(null);
            lastKnownLocation = null;
        }
        else
        {
            Point p = new Point(x, y);
            overlay.setPreferredLocation(p);
            lastKnownLocation = p;
        }
    }

    /**
     * Called by the overlay when the user finishes an Alt+drag, so the config sliders
     * reflect where they dropped it.
     */
    public void persistDraggedPosition(Point p)
    {
        if (p == null) return;
        config.positionX(p.x);
        config.positionY(p.y);
    }

    @Subscribe
    public void onGameTick(GameTick event)
    {
        // Detect Alt+drag moves: if the overlay's current preferred location differs
        // from what we last saved, persist it so the sliders reflect reality.
        Point currentLoc = overlay.getPreferredLocation();
        if (currentLoc != null && !currentLoc.equals(lastKnownLocation))
        {
            lastKnownLocation = new Point(currentLoc);
            // Only persist if this looks like a user drag (not our own config-driven update).
            if (currentLoc.x != config.positionX() || currentLoc.y != config.positionY())
            {
                persistDraggedPosition(currentLoc);
            }
        }

        Widget npcText = client.getWidget(ComponentID.DIALOG_NPC_TEXT);
        Widget npcName = client.getWidget(ComponentID.DIALOG_NPC_NAME);
        Widget playerText = client.getWidget(ComponentID.DIALOG_PLAYER_TEXT);
        Widget options = client.getWidget(ComponentID.DIALOG_OPTION_OPTIONS);
        Widget spriteText = client.getWidget(ComponentID.DIALOG_SPRITE_TEXT);
        Widget doubleSpriteText = client.getWidget(ComponentID.DIALOG_DOUBLE_SPRITE_TEXT);

        boolean npcVisible = isVisible(npcText);
        boolean playerVisible = isVisible(playerText);
        boolean optionsVisible = isVisible(options);
        boolean emoteVisible = isVisible(spriteText) || isVisible(doubleSpriteText);

        // Continue-style dialogue (tap to continue) reuses the same NPC_TEXT widget,
        // so it's handled by the npcVisible branch.

        if (!npcVisible && !playerVisible && !optionsVisible && !emoteVisible)
        {
            // Nothing on screen — conversation ended or never started. We check BOTH
            // state and currentLine here because emote/sprite dialogue (e.g. Motherlode
            // hopper, item use messages) sets currentLine without advancing the state
            // machine out of IDLE. Without the currentLine check, walking away from an
            // emote would leave it stuck on the overlay indefinitely.
            if (state != DialogueState.IDLE || currentLine != null)
            {
                resetConversation();
            }
            return;
        }

        // Emote/sprite messages exist alongside their own widget tree; they don't
        // interact with the NPC/player/option state machine. Handle them first, and
        // if an emote is visible, render it and skip the rest of the state logic.
        if (emoteVisible)
        {
            Widget emoteWidget = isVisible(spriteText) ? spriteText : doubleSpriteText;
            String emoteRaw = emoteWidget.getText();
            String cleaned = cleanText(emoteRaw);
            if (!cleaned.isEmpty())
            {
                // Only update if text changed, so we don't churn the currentLine object every tick.
                if (currentLine == null
                    || currentLine.getKind() != DialogueLine.Kind.EMOTE
                    || !cleaned.equals(currentLine.getText()))
                {
                    currentLine = DialogueLine.emote(cleaned);
                }
            }
            return;
        }

        switch (state)
        {
            case IDLE:
                if (npcVisible)
                {
                    enterNpcSpeaking(npcName, npcText);
                }
                else if (playerVisible)
                {
                    // Some chains open with the player speaking first.
                    enterPlayerSpeaking(playerText);
                }
                else if (optionsVisible)
                {
                    enterAwaitingChoice(options);
                }
                break;

            case NPC_SPEAKING:
                if (optionsVisible)
                {
                    enterAwaitingChoice(options);
                }
                else if (playerVisible)
                {
                    // Rare: NPC line directly followed by a player-spoken line without options.
                    enterPlayerSpeaking(playerText);
                }
                else if (npcVisible)
                {
                    // Multi-page NPC dialogue — text or speaker may have changed.
                    String newText = cleanText(npcText.getText());
                    String newName = npcName != null ? cleanText(npcName.getText()) : null;
                    if (!equalsNullable(newText, lastNpcText) || !equalsNullable(newName, lastNpcName))
                    {
                        enterNpcSpeaking(npcName, npcText);
                    }
                }
                break;

            case AWAITING_CHOICE:
                if (!optionsVisible)
                {
                    // Options closed; the player clicked one.
                    enterPlayerChose();
                }
                // While options are visible, just keep the current NPC line on screen.
                break;

            case PLAYER_CHOSE:
                if (npcVisible)
                {
                    enterNpcSpeaking(npcName, npcText);
                }
                else if (optionsVisible)
                {
                    enterAwaitingChoice(options);
                }
                else if (playerVisible)
                {
                    enterPlayerSpeaking(playerText);
                }
                break;
        }
    }

    // =========================================================================
    // State transitions
    // =========================================================================

    private void enterNpcSpeaking(Widget nameWidget, Widget textWidget)
    {
        String name = nameWidget != null ? cleanText(nameWidget.getText()) : null;
        String text = cleanText(textWidget.getText());

        lastNpcName = name;
        lastNpcText = text;

        currentLine = DialogueLine.npc(name, text);
        state = DialogueState.NPC_SPEAKING;
    }

    private void enterPlayerSpeaking(Widget textWidget)
    {
        String text = cleanText(textWidget.getText());
        currentLine = DialogueLine.player(getLocalPlayerName(), text);
        state = DialogueState.NPC_SPEAKING; // treat player-spoken widgets like NPC lines for flow
    }

    private void enterAwaitingChoice(Widget optionsWidget)
    {
        // We don't render the option text ourselves — OSRS's own chatbox shows it.
        // We only track the state so we know when the player has clicked a choice.
        state = DialogueState.AWAITING_CHOICE;
    }

    private void enterPlayerChose()
    {
        state = DialogueState.PLAYER_CHOSE;

        // If DIALOG_PLAYER_TEXT is visible this tick, the chosen option's text lives there.
        Widget playerText = client.getWidget(ComponentID.DIALOG_PLAYER_TEXT);
        if (isVisible(playerText))
        {
            currentLine = DialogueLine.player(getLocalPlayerName(), cleanText(playerText.getText()));
        }
    }

    private void resetConversation()
    {
        state = DialogueState.IDLE;
        currentLine = null;
        lastNpcText = null;
        lastNpcName = null;
    }

    // =========================================================================
    // Widget helpers
    // =========================================================================

    private static boolean isVisible(Widget w)
    {
        return w != null && !w.isHidden();
    }

    /**
     * Strips OSRS color/formatting tags (e.g. {@code <col=ffffff>}, {@code <br>}) from
     * raw widget text. {@code <br>} tags become spaces so the overlay's word-wrap can
     * re-flow the text to the configured window width — OSRS inserts these tags based
     * on its own narrow dialogue box and they don't reflect intentional paragraph breaks.
     */
    static String cleanText(String raw)
    {
        if (raw == null) return "";
        // Replace <br> with a space so the wrapper can re-flow at our window width.
        String s = raw.replaceAll("(?i)<br\\s*/?>", " ");
        // Strip all remaining tags like <col=xxxxxx>, </col>, <img=...>, etc.
        s = s.replaceAll("<[^>]+>", "");
        // Collapse nbsp.
        s = s.replace('\u00A0', ' ');
        // Collapse any runs of whitespace introduced by tag stripping.
        s = s.replaceAll("\\s+", " ");
        return s.trim();
    }

    private static boolean equalsNullable(String a, String b)
    {
        return a == null ? b == null : a.equals(b);
    }

    private String getLocalPlayerName()
    {
        Player p = client.getLocalPlayer();
        if (p != null && p.getName() != null && !p.getName().isEmpty())
        {
            return p.getName();
        }
        return "You";
    }

    // =========================================================================
    // Font loading
    // =========================================================================

    private void loadFonts()
    {
        GraphicsEnvironment ge = GraphicsEnvironment.getLocalGraphicsEnvironment();
        for (FontChoice choice : FontChoice.values())
        {
            String path = choice.getResourcePath();
            if (path == null)
            {
                // No resource bundled — use the platform logical font directly.
                loadedFonts.put(choice, fallbackFor(choice));
                continue;
            }

            try (InputStream in = getClass().getClassLoader().getResourceAsStream(path))
            {
                if (in == null)
                {
                    log.warn("Font resource missing: {} — falling back to {}.", path, choice.getLogicalName());
                    loadedFonts.put(choice, fallbackFor(choice));
                    continue;
                }
                Font f = Font.createFont(Font.TRUETYPE_FONT, in);
                ge.registerFont(f);
                loadedFonts.put(choice, f);
            }
            catch (Exception e)
            {
                log.warn("Failed to load font {}: {}", choice, e.getMessage());
                loadedFonts.put(choice, fallbackFor(choice));
            }
        }
    }

    private static Font fallbackFor(FontChoice choice)
    {
        return new Font(choice.getLogicalName(), Font.PLAIN, 16);
    }

    /**
     * Returns the loaded (or fallback) base font for the given choice, derived to the
     * configured size and weight. Called by the overlay every frame.
     */
    public Font getConfiguredFont()
    {
        Font base = loadedFonts.getOrDefault(config.fontChoice(), fallbackFor(config.fontChoice()));
        int style = config.fontBold() ? Font.BOLD : Font.PLAIN;
        return base.deriveFont(style, config.fontSize());
    }
}

package com.divinedialogue;

import java.awt.BasicStroke;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Font;
import java.awt.FontMetrics;
import java.awt.Graphics2D;
import java.awt.RenderingHints;
import java.awt.Stroke;
import java.awt.image.BufferedImage;
import java.util.ArrayList;
import java.util.List;
import javax.inject.Inject;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;

public class DivineDialogueOverlay extends Overlay
{
    private final DivineDialogueConfig config;
    private final GradientRenderer gradient = new GradientRenderer();

    /** Set by the plugin on startup. */
    private DivineDialoguePlugin plugin;

    // --- Typewriter state.
    /** Identity of the line currently being typed, used to detect when to reset. */
    private String typewriterLineKey = null;
    /** Wall-clock time the current line began revealing. */
    private long typewriterStartMillis = 0L;
    /** Number of characters revealed in the previous render pass, for new-char detection. */
    private int lastRevealedCount = 0;
    /** Last time we played a typewriter sound, for throttling. */
    private long lastSoundMillis = 0L;

    @Inject
    public DivineDialogueOverlay(DivineDialogueConfig config)
    {
        this.config = config;
        setPosition(OverlayPosition.BOTTOM_RIGHT);
        setLayer(OverlayLayer.ABOVE_WIDGETS);
        // Let the user drag it with Alt+drag (RuneLite default for movable overlays).
        setMovable(true);
        setResettable(true);
        setSnappable(true);
    }

    public void setPlugin(DivineDialoguePlugin plugin)
    {
        this.plugin = plugin;
    }

    public void invalidateGradientCache()
    {
        gradient.invalidate();
    }

    @Override
    public Dimension render(Graphics2D g)
    {
        if (plugin == null)
        {
            return null;
        }
        DialogueLine line = plugin.getCurrentLine();
        if (line == null)
        {
            // Clear typewriter state so the next line starts fresh.
            typewriterLineKey = null;
            return null;
        }

        boolean isEmote = line.getKind() == DialogueLine.Kind.EMOTE;
        boolean isPlayer = line.getKind() == DialogueLine.Kind.PLAYER;

        // --- Font selection.
        Font font = plugin.getConfiguredFont();
        if (isEmote && config.emoteItalic())
        {
            font = font.deriveFont(font.getStyle() | Font.ITALIC);
        }
        g.setFont(font);
        FontMetrics fm = g.getFontMetrics(font);

        int width = Math.max(80, config.windowWidth());
        int padding = Math.max(0, config.windowPadding());
        int innerWidth = Math.max(1, width - padding * 2);

        // --- Conversation Mode: decide horizontal offset inside the overlay's bounds.
        // Emotes ignore the mode (they're neither NPC nor player voice).
        boolean conversationActive = config.conversationMode() && !isEmote;
        int conversationOffset = conversationActive ? Math.max(0, config.conversationOffset()) : 0;
        // Total bounding box width accommodates the shift so drag bounds stay predictable.
        int boundsWidth = width + (conversationActive ? conversationOffset * 2 : 0);
        // x-origin where the backdrop/text block starts drawing inside the bounds.
        int contentX;
        if (!conversationActive)
        {
            contentX = 0;
        }
        else if (isPlayer)
        {
            contentX = conversationOffset * 2; // player pushed right
        }
        else
        {
            contentX = 0; // NPC pushed left
        }

        // --- Typewriter: compute how many characters of the body text to reveal.
        String fullBody = line.getText() == null ? "" : line.getText();
        String displayBody = fullBody;
        if (config.typewriterMode() && !isEmote)
        {
            String lineKey = line.getKind() + "|" + line.getSpeaker() + "|" + fullBody;
            long now = System.currentTimeMillis();
            if (!lineKey.equals(typewriterLineKey))
            {
                typewriterLineKey = lineKey;
                typewriterStartMillis = now;
                lastRevealedCount = 0;
            }
            int speed = Math.max(1, config.typewriterSpeed());
            long elapsed = Math.max(0, now - typewriterStartMillis);
            int revealed = (int) Math.min(fullBody.length(), (elapsed * speed) / 1000L);
            displayBody = fullBody.substring(0, revealed);

            // Play a click sound if new characters appeared this frame, we're not
            // past the throttle window, and the newest character isn't whitespace.
            TypewriterSound sound = config.typewriterSound();
            if (sound != null && sound != TypewriterSound.NONE && revealed > lastRevealedCount)
            {
                int interval = Math.max(1, config.typewriterSoundInterval());
                if (now - lastSoundMillis >= interval)
                {
                    char justRevealed = fullBody.charAt(revealed - 1);
                    if (!Character.isWhitespace(justRevealed))
                    {
                        plugin.getSoundPlayer().play(sound, config.typewriterVolume());
                        lastSoundMillis = now;
                    }
                }
            }
            lastRevealedCount = revealed;
        }
        else
        {
            // If typewriter is off, clear the tracker so toggling it back on starts fresh.
            typewriterLineKey = null;
            lastRevealedCount = 0;
        }

        // --- Layout pass: wrap text to figure out final height.
        List<String> wrapped = new ArrayList<>();

        String speakerLine = isEmote ? null : buildSpeakerLine(line);
        if (speakerLine != null)
        {
            wrapped.addAll(wrap(speakerLine, fm, innerWidth));
        }

        wrapped.addAll(wrap(displayBody, fm, innerWidth));

        int lineHeight = fm.getHeight();
        int textBlockHeight = Math.max(lineHeight, wrapped.size() * lineHeight);
        int height = textBlockHeight + padding * 2;

        // --- Paint: backdrop & border skipped for emotes.
        if (!isEmote)
        {
            BufferedImage bg = gradient.render(
                config.cornerTopLeft(),
                config.cornerTopRight(),
                config.cornerBottomLeft(),
                config.cornerBottomRight(),
                config.backdropOpacity(),
                width, height);
            if (bg != null)
            {
                g.drawImage(bg, contentX, 0, null);
            }

            if (config.borderEnabled() && config.borderThickness() > 0)
            {
                Stroke old = g.getStroke();
                g.setStroke(new BasicStroke(config.borderThickness()));
                g.setColor(config.borderColor());
                int t = config.borderThickness();
                g.drawRect(contentX + t / 2, t / 2,
                    width - Math.max(1, t), height - Math.max(1, t));
                g.setStroke(old);
            }
        }

        Object oldAntialias = g.getRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING);
        g.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, RenderingHints.VALUE_TEXT_ANTIALIAS_ON);
        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

        int x = contentX + padding;
        int y = padding + fm.getAscent();
        int idx = 0;

        if (speakerLine != null)
        {
            Color speakerColor = isPlayer ? config.playerTextColor() : config.npcTextColor();
            Font boldFont = font.deriveFont(Font.BOLD, font.getSize2D());
            g.setFont(boldFont);
            FontMetrics boldFm = g.getFontMetrics(boldFont);
            List<String> speakerWrapped = wrap(speakerLine, boldFm, innerWidth);
            for (String sl : speakerWrapped)
            {
                drawStyledText(g, sl, x, y, speakerColor);
                y += lineHeight;
                idx++;
            }
            g.setFont(font);
        }

        Color bodyColor;
        switch (line.getKind())
        {
            case PLAYER:
                bodyColor = config.playerTextColor();
                break;
            case EMOTE:
                bodyColor = config.emoteTextColor();
                break;
            case NPC:
            default:
                bodyColor = config.npcTextColor();
                break;
        }

        for (int i = idx; i < wrapped.size(); i++)
        {
            drawStyledText(g, wrapped.get(i), x, y, bodyColor);
            y += lineHeight;
        }

        g.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, oldAntialias);

        return new Dimension(boundsWidth, height);
    }

    private String buildSpeakerLine(DialogueLine line)
    {
        if (line.getSpeaker() == null || line.getSpeaker().isEmpty())
        {
            return null;
        }
        return line.getSpeaker() + ":";
    }

    private void drawStyledText(Graphics2D g, String text, int x, int y, Color fillColor)
    {
        if (text == null || text.isEmpty())
        {
            return;
        }
        if (config.strokeEnabled() && config.strokeWidth() > 0)
        {
            int sw = config.strokeWidth();
            g.setColor(config.strokeColor());
            // Cheap 8-direction stroke; good enough at 1-3 px and avoids TextLayout overhead.
            for (int dx = -sw; dx <= sw; dx++)
            {
                for (int dy = -sw; dy <= sw; dy++)
                {
                    if (dx == 0 && dy == 0) continue;
                    g.drawString(text, x + dx, y + dy);
                }
            }
        }
        g.setColor(fillColor);
        g.drawString(text, x, y);
    }

    /**
     * Naive word-wrap that also respects embedded newlines (from stripped {@code <br>} tags).
     * Falls back to hard-splitting words longer than the available width.
     */
    static List<String> wrap(String text, FontMetrics fm, int maxWidth)
    {
        List<String> out = new ArrayList<>();
        if (text == null || text.isEmpty())
        {
            out.add("");
            return out;
        }

        String[] paragraphs = text.split("\n", -1);
        for (String paragraph : paragraphs)
        {
            if (paragraph.isEmpty())
            {
                out.add("");
                continue;
            }
            String[] words = paragraph.split(" ");
            StringBuilder cur = new StringBuilder();
            for (String word : words)
            {
                String probe = cur.length() == 0 ? word : cur + " " + word;
                if (fm.stringWidth(probe) <= maxWidth)
                {
                    if (cur.length() == 0)
                    {
                        cur.append(word);
                    }
                    else
                    {
                        cur.append(' ').append(word);
                    }
                }
                else
                {
                    if (cur.length() > 0)
                    {
                        out.add(cur.toString());
                        cur.setLength(0);
                    }
                    // Word itself may be too long; hard-split.
                    if (fm.stringWidth(word) > maxWidth)
                    {
                        StringBuilder chunk = new StringBuilder();
                        for (int i = 0; i < word.length(); i++)
                        {
                            chunk.append(word.charAt(i));
                            if (fm.stringWidth(chunk.toString()) > maxWidth)
                            {
                                chunk.deleteCharAt(chunk.length() - 1);
                                out.add(chunk.toString());
                                chunk.setLength(0);
                                chunk.append(word.charAt(i));
                            }
                        }
                        if (chunk.length() > 0)
                        {
                            cur.append(chunk);
                        }
                    }
                    else
                    {
                        cur.append(word);
                    }
                }
            }
            if (cur.length() > 0)
            {
                out.add(cur.toString());
            }
        }
        return out;
    }
}

