package com.divinedialogue;

import java.util.Collections;
import java.util.List;

/**
 * Config-facing enum for the typewriter sound selector. Each option (besides
 * {@link #NONE}) resolves to a list of sample variant paths; one is picked at
 * random on each play to give the typewriter a natural, non-robotic feel.
 *
 * <p>Variants are named {@code typeNa.wav, typeNb.wav, typeNc.wav, typeNd.wav}
 * where N is the option number. All four files are expected to exist on the
 * classpath; {@link SoundPlayer} logs a warning and skips a missing variant
 * without breaking the others.</p>
 */
public enum TypewriterSound
{
    NONE("None", Collections.emptyList()),
    OPTION_A("Option A", List.of(
        "sounds/type1a.wav",
        "sounds/type1b.wav",
        "sounds/type1c.wav",
        "sounds/type1d.wav"
    )),
    OPTION_B("Option B", List.of(
        "sounds/type2a.wav",
        "sounds/type2b.wav",
        "sounds/type2c.wav",
        "sounds/type2d.wav"
    ));

    private final String displayName;
    private final List<String> variantPaths;

    TypewriterSound(String displayName, List<String> variantPaths)
    {
        this.displayName = displayName;
        this.variantPaths = variantPaths;
    }

    /**
     * Returns the list of classpath resource paths this option can play.
     * Empty for {@link #NONE}. Never null.
     */
    public List<String> getVariantPaths()
    {
        return variantPaths;
    }

    @Override
    public String toString()
    {
        return displayName;
    }
}

package com.divinedialogue;

import lombok.Value;

/**
 * A single rendered line in the overlay.
 *
 * <p>{@link #speaker} is the NPC's display name for NPC lines, the local player's
 * name for player echo lines, or null for emote/continue-style lines with no
 * speaker label.</p>
 */
@Value
public class DialogueLine
{
    public enum Kind
    {
        /** Regular NPC dialogue — backdrop, border, NPC text color. */
        NPC,
        /** Player-spoken line or echoed choice — backdrop, border, player text color. */
        PLAYER,
        /** Emote/sprite dialogue (e.g. "Arthur's eyes light up") — no backdrop, no border, own color. */
        EMOTE
    }

    Kind kind;
    String speaker;
    String text;

    public static DialogueLine npc(String speaker, String text)
    {
        return new DialogueLine(Kind.NPC, speaker, text);
    }

    public static DialogueLine player(String speaker, String text)
    {
        return new DialogueLine(Kind.PLAYER, speaker, text);
    }

    public static DialogueLine emote(String text)
    {
        return new DialogueLine(Kind.EMOTE, null, text);
    }

    /** True only for PLAYER kind. */
    public boolean isPlayer()
    {
        return kind == Kind.PLAYER;
    }
}

