package com.prayerloadouts;

import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.api.Skill;
import net.runelite.api.events.GameStateChanged;
import net.runelite.api.events.VarbitChanged;
import net.runelite.api.gameval.VarbitID;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.eventbus.Subscribe;
import net.runelite.client.events.PluginChanged;
import net.runelite.client.game.SkillIconManager;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDependency;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.plugins.prayer.PrayerPlugin;
import net.runelite.client.ui.ClientToolbar;
import net.runelite.client.ui.NavigationButton;

import javax.inject.Inject;
import java.awt.image.BufferedImage;
import java.util.Set;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.function.Consumer;

@PluginDependency(PrayerPlugin.class)
@PluginDescriptor(name = "Prayer Loadouts", description = "Save and load named prayer book arrangements", tags = {
        "prayer", "loadout", "reorder", "preset" })
public class PrayerLoadoutsPlugin extends Plugin {

    @Inject
    private Client client;

    @Inject
    private ClientThread clientThread;

    @Inject
    private ClientToolbar clientToolbar;

    @Inject
    private SkillIconManager skillIconManager;

    @Inject
    private LoadoutManager loadoutManager;

    @Inject
    private LoadoutSerializer loadoutSerializer;

    @Inject
    private PrayerStateManager prayerStateManager;

    @Inject
    private ScheduledExecutorService executor;

    private PrayerLoadoutsPanel panel;
    private NavigationButton navButton;
    private volatile boolean loggedIn = false;

    @Override
    protected void startUp() {
        // Check initial login state and update cache if already logged in
        clientThread.invokeLater(() -> {
            loggedIn = client.getGameState() == GameState.LOGGED_IN;
            if (loggedIn) {
                loadoutManager.updateCachedFilters();
            }
        });

        // Create and register the panel
        panel = new PrayerLoadoutsPanel(this);
        final BufferedImage icon = skillIconManager.getSkillImage(Skill.PRAYER);
        navButton = NavigationButton.builder()
                .tooltip("Prayer Loadouts")
                .icon(icon)
                .priority(6)
                .panel(panel)
                .build();
        clientToolbar.addNavigation(navButton);
    }

    @Override
    protected void shutDown() {
        clientToolbar.removeNavigation(navButton);
        panel = null;
        navButton = null;
    }

    @Subscribe
    public void onGameStateChanged(GameStateChanged event) {
        GameState state = event.getGameState();
        boolean wasLoggedIn = loggedIn;
        loggedIn = (state == GameState.LOGGED_IN);

        if (wasLoggedIn != loggedIn) {
            refreshPanel();

            // Auto-load last loadout on login (delayed to allow game to fully load)
            if (loggedIn) {
                executor.schedule(() -> clientThread.invokeLater(() -> {
                    // Update cache first to get current state
                    loadoutManager.updateCachedFilters();

                    String lastLoadout = loadoutManager.getLastLoadoutName();
                    if (lastLoadout != null && !lastLoadout.isEmpty()
                            && loadoutManager.getLoadoutNames().contains(lastLoadout)) {
                        // Pass callback to refresh panel after cache is updated
                        boolean success = loadoutManager.loadLoadout(lastLoadout, this::refreshPanel);
                        if (!success) {
                            // Refresh panel even if load failed (cache already updated above)
                            refreshPanel();
                        }
                        // Panel is refreshed via callback if load succeeded
                    } else {
                        // No loadout to load, just refresh panel
                        refreshPanel();
                    }
                }), 2, TimeUnit.SECONDS);
            }
        }
    }

    @Subscribe
    public void onPluginChanged(PluginChanged event) {
        // Refresh the panel when the Prayer plugin is enabled or disabled
        if (event.getPlugin() instanceof PrayerPlugin) {
            refreshPanel();
        }
    }

    @Subscribe
    public void onVarbitChanged(VarbitChanged event) {
        int varbitId = event.getVarbitId();

        // Update cache when filter varbits change (keeps active loadout detection accurate)
        if (varbitId == VarbitID.PRAYER_FILTER_BLOCKLOWTIER ||
            varbitId == VarbitID.PRAYER_FILTER_ALLOWCOMBINEDTIER ||
            varbitId == VarbitID.PRAYER_FILTER_BLOCKHEALING ||
            varbitId == VarbitID.PRAYER_FILTER_BLOCKLACKLEVEL ||
            varbitId == VarbitID.PRAYER_FILTER_BLOCKLOCKED ||
            varbitId == VarbitID.PRAYER_HIDEFILTERBUTTON) {

            clientThread.invokeLater(() -> {
                loadoutManager.updateCachedFilters();
                refreshPanel();
            });
        }
    }

    public boolean isLoggedIn() {
        return loggedIn;
    }

    public boolean isPrayerPluginEnabled() {
        return prayerStateManager.isPrayerPluginEnabled();
    }

    public Set<String> getLoadoutNames() {
        return loadoutManager.getLoadoutNames();
    }

    public String getActiveLoadoutName() {
        return loadoutManager.getActiveLoadoutName(loggedIn);
    }

    public void saveLoadoutFromPanel(String name) {
        clientThread.invokeLater(() -> {
            loadoutManager.saveLoadout(name);
            loadoutManager.updateCachedFilters();
            refreshPanel();
        });
    }

    /**
     * Loads a loadout asynchronously. Calls the callback with true on success, false on failure.
     * This method does not block the Swing EDT.
     */
    public void loadLoadoutFromPanel(String name, Consumer<Boolean> callback) {
        clientThread.invokeLater(() -> {
            boolean success = loadoutManager.loadLoadout(name, this::refreshPanel);
            if (!success) {
                // Refresh panel even on failure
                refreshPanel();
            }
            // Notify the caller of the result on the Swing EDT
            if (callback != null) {
                javax.swing.SwingUtilities.invokeLater(() -> callback.accept(success));
            }
        });
    }

    public boolean exportLoadoutFromPanel(String name) {
        return loadoutSerializer.exportLoadout(name);
    }

    public void deleteLoadoutFromPanel(String name) {
        loadoutManager.deleteLoadout(name);
        refreshPanel();
    }

    public void renameLoadoutFromPanel(String oldName, String newName) {
        loadoutManager.renameLoadout(oldName, newName);
        refreshPanel();
    }

    public boolean importLoadoutFromPanel(String name) {
        boolean success = loadoutSerializer.importLoadout(name);
        refreshPanel();
        return success;
    }

    public void resetToDefaultsFromPanel() {
        clientThread.invokeLater(() -> {
            loadoutManager.resetToDefaults();
            // Update cache after a brief delay to allow varbits to be set
            executor.schedule(() -> clientThread.invokeLater(() -> {
                loadoutManager.updateCachedFilters();
                refreshPanel();
            }), 150, TimeUnit.MILLISECONDS);
        });
    }

    private void refreshPanel() {
        if (panel != null) {
            panel.rebuild();
        }
    }

}

package com.prayerloadouts;

import net.runelite.client.ui.ColorScheme;
import net.runelite.client.ui.PluginPanel;
import net.runelite.client.ui.FontManager;

import javax.swing.Box;
import javax.swing.BoxLayout;
import javax.swing.JButton;
import javax.swing.JLabel;
import javax.swing.JOptionPane;
import javax.swing.JPanel;
import javax.swing.JScrollPane;
import javax.swing.ScrollPaneConstants;
import javax.swing.SwingConstants;
import javax.swing.border.EmptyBorder;

import java.awt.BorderLayout;
import java.awt.Color;
import java.awt.Component;
import java.awt.Dimension;
import java.awt.FlowLayout;
import java.awt.Font;
import java.awt.GridLayout;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;
import java.util.Set;

public class PrayerLoadoutsPanel extends PluginPanel {
    private final PrayerLoadoutsPlugin plugin;

    // Fixed sections (created once, visibility controlled)
    private final JPanel savePanel;
    private final JPanel footerSection;

    // Scrollable content (rebuilt on state change)
    private final JPanel scrollableContent;

    // Reusable info panels
    private final JPanel noLoadoutsPanel;
    private final JPanel loginRequiredPanel;
    private final JPanel prayerPluginRequiredPanel;

    // ========== Section Builders ==========

    private JPanel createHeaderSection() {
        JPanel section = new JPanel(new BorderLayout());
        section.setBackground(ColorScheme.DARK_GRAY_COLOR);
        section.setBorder(new EmptyBorder(10, 10, 10, 10));
        section.setPreferredSize(new Dimension(0, 42));

        // Title on the left
        JLabel title = new JLabel("Prayer Loadouts");
        title.setForeground(Color.WHITE);
        title.setFont(title.getFont().deriveFont(Font.BOLD, 16f));
        section.add(title, BorderLayout.WEST);

        // Buttons on the right
        JPanel buttonsPanel = new JPanel(new FlowLayout(FlowLayout.RIGHT, 5, 0));
        buttonsPanel.setBackground(ColorScheme.DARK_GRAY_COLOR);

        JButton refreshButton = new JButton("↻");
        refreshButton.setToolTipText("Refresh loadout list");
        refreshButton.addActionListener(e -> rebuild());
        buttonsPanel.add(refreshButton);

        section.add(buttonsPanel, BorderLayout.EAST);

        return section;
    }

    private JPanel createSavePanel() {
        JPanel panel = new JPanel(new GridLayout(1, 2, 5, 0));
        panel.setBackground(ColorScheme.DARK_GRAY_COLOR);
        panel.setBorder(new EmptyBorder(0, 10, 10, 10));

        JButton saveButton = new JButton("Save");
        saveButton.setBackground(new Color(0, 150, 0));
        saveButton.setForeground(Color.WHITE);
        saveButton.setToolTipText("Save current prayer arrangement as a loadout");
        saveButton.addActionListener(e -> {
            String name = JOptionPane.showInputDialog(this,
                    "Enter a name for this loadout:",
                    "Save Loadout",
                    JOptionPane.PLAIN_MESSAGE);

            if (name == null) {
                return; // User cancelled
            }

            name = name.trim();
            if (name.isEmpty()) {
                JOptionPane.showMessageDialog(this,
                        "Please enter a name for the loadout.",
                        "Name Required",
                        JOptionPane.WARNING_MESSAGE);
                return;
            }

            if (plugin.getLoadoutNames().contains(name)) {
                int confirm = JOptionPane.showConfirmDialog(this,
                        "Loadout '" + name + "' already exists. Overwrite?",
                        "Confirm Overwrite",
                        JOptionPane.YES_NO_OPTION,
                        JOptionPane.WARNING_MESSAGE);
                if (confirm != JOptionPane.YES_OPTION) {
                    return;
                }
            }

            plugin.saveLoadoutFromPanel(name);
        });
        panel.add(saveButton);

        JButton defaultsButton = new JButton("Defaults");
        defaultsButton.setToolTipText("Reset prayer book to vanilla OSRS defaults");
        defaultsButton.addActionListener(e -> {
            int confirm = JOptionPane.showConfirmDialog(this,
                    "Reset prayer book to default OSRS layout?\nThis will clear custom ordering, hidden prayers, and filters.",
                    "Confirm Reset",
                    JOptionPane.YES_NO_OPTION,
                    JOptionPane.WARNING_MESSAGE);
            if (confirm == JOptionPane.YES_OPTION) {
                plugin.resetToDefaultsFromPanel();
            }
        });
        panel.add(defaultsButton);

        return panel;
    }

    private JPanel createFooterSection() {
        JPanel section = new JPanel(new BorderLayout());
        section.setBackground(ColorScheme.DARK_GRAY_COLOR);
        section.setBorder(new EmptyBorder(10, 10, 10, 10));

        JButton importButton = new JButton("Import from Clipboard");
        importButton.setToolTipText("Import a loadout from clipboard data");
        importButton.addActionListener(e -> {
            String name = JOptionPane.showInputDialog(this,
                    "Enter name for imported loadout (leave blank to use original):",
                    "Import Loadout",
                    JOptionPane.PLAIN_MESSAGE);
            if (name != null) {
                boolean success = plugin.importLoadoutFromPanel(name.isEmpty() ? null : name);
                if (!success) {
                    JOptionPane.showMessageDialog(this,
                            "Invalid clipboard data. Make sure you copied a valid loadout export.",
                            "Import Failed",
                            JOptionPane.ERROR_MESSAGE);
                }
            }
        });
        section.add(importButton, BorderLayout.CENTER);

        return section;
    }

    /**
     * Creates a centered info panel with optional icon, title, and description.
     * Used for status messages like "Login Required", "No loadouts", etc.
     */
    private static JPanel createInfoPanel(String icon, Color iconColor, String title, String description) {
        JPanel panel = new JPanel();
        panel.setLayout(new BoxLayout(panel, BoxLayout.Y_AXIS));
        panel.setBackground(ColorScheme.DARK_GRAY_COLOR);
        panel.setBorder(new EmptyBorder(20, 10, 20, 10));
        panel.setAlignmentX(Component.LEFT_ALIGNMENT);

        // Icon (optional)
        if (icon != null) {
            JLabel iconLabel = new JLabel(icon);
            iconLabel.setFont(iconLabel.getFont().deriveFont(32f));
            iconLabel.setAlignmentX(Component.CENTER_ALIGNMENT);
            if (iconColor != null) {
                iconLabel.setForeground(iconColor);
            }
            panel.add(iconLabel);
            panel.add(Box.createRigidArea(new Dimension(0, 10)));
        }

        // Title
        JLabel titleLabel = new JLabel(title);
        titleLabel.setForeground(Color.WHITE);
        titleLabel.setFont(titleLabel.getFont().deriveFont(Font.BOLD, 14f));
        titleLabel.setAlignmentX(Component.CENTER_ALIGNMENT);
        panel.add(titleLabel);
        panel.add(Box.createRigidArea(new Dimension(0, 5)));

        // Description
        JLabel descLabel = new JLabel("<html><center>" + description + "</center></html>");
        descLabel.setForeground(Color.GRAY);
        descLabel.setAlignmentX(Component.CENTER_ALIGNMENT);
        descLabel.setHorizontalAlignment(SwingConstants.CENTER);
        panel.add(descLabel);

        return panel;
    }

    /**
     * Creates a loadout card panel with name, load button, and action buttons.
     */
    private static final Color ACTIVE_COLOR = new Color(0, 100, 0);
    private static final Color ACTIVE_HOVER_COLOR = new Color(0, 130, 0);

    private JPanel createLoadoutPanel(String name, boolean isActive) {
        final Color bgColor = isActive ? ACTIVE_COLOR : ColorScheme.DARKER_GRAY_COLOR;
        final Color hoverColor = isActive ? ACTIVE_HOVER_COLOR : ColorScheme.DARKER_GRAY_HOVER_COLOR;

        JPanel panel = new JPanel();
        panel.setLayout(new BoxLayout(panel, BoxLayout.Y_AXIS));
        panel.setBackground(bgColor);
        panel.setBorder(new EmptyBorder(8, 10, 8, 10));
        panel.setMaximumSize(new Dimension(Integer.MAX_VALUE, 70));

        String displayName = isActive ? "● " + name : name;
        JLabel nameLabel = new JLabel(displayName);
        nameLabel.setForeground(isActive ? new Color(144, 238, 144) : Color.WHITE);
        nameLabel.setFont(FontManager.getRunescapeFont());
        nameLabel.setAlignmentX(Component.LEFT_ALIGNMENT);
        panel.add(nameLabel);

        panel.add(Box.createRigidArea(new Dimension(0, 5)));

        JPanel buttonsPanel = new JPanel(new FlowLayout(FlowLayout.LEFT, 3, 0));
        buttonsPanel.setBackground(bgColor);
        buttonsPanel.setAlignmentX(Component.LEFT_ALIGNMENT);

        JButton loadButton = new JButton("Load");
        loadButton.setBackground(ColorScheme.BRAND_ORANGE);
        loadButton.setToolTipText("Load this prayer arrangement");
        loadButton.addActionListener(e -> {
            // Async load - callback handles success/failure
            plugin.loadLoadoutFromPanel(name, success -> {
                if (!success) {
                    JOptionPane.showMessageDialog(this,
                            "This loadout has no data for your current prayerbook.\nTry saving it again.",
                            "Load Failed",
                            JOptionPane.WARNING_MESSAGE);
                }
            });
        });
        buttonsPanel.add(loadButton);

        JButton exportButton = new JButton("📋");
        exportButton.setToolTipText("Copy to clipboard");
        exportButton.addActionListener(e -> {
            boolean success = plugin.exportLoadoutFromPanel(name);
            if (!success) {
                JOptionPane.showMessageDialog(this,
                        "This loadout has no data to export.\nTry saving it again.",
                        "Export Failed",
                        JOptionPane.WARNING_MESSAGE);
            }
        });
        buttonsPanel.add(exportButton);

        JButton renameButton = new JButton("✏");
        renameButton.setToolTipText("Rename this loadout");
        renameButton.addActionListener(e -> {
            String newName = (String) JOptionPane.showInputDialog(
                    this,
                    "Enter new name for '" + name + "':",
                    "Rename Loadout",
                    JOptionPane.PLAIN_MESSAGE,
                    null,
                    null,
                    name);
            if (newName != null && !newName.trim().isEmpty() && !newName.equals(name)) {
                newName = newName.trim();
                if (plugin.getLoadoutNames().contains(newName)) {
                    JOptionPane.showMessageDialog(this,
                            "A loadout named '" + newName + "' already exists.",
                            "Name Already Exists",
                            JOptionPane.ERROR_MESSAGE);
                    return;
                }
                plugin.renameLoadoutFromPanel(name, newName);
            }
        });
        buttonsPanel.add(renameButton);

        JButton deleteButton = new JButton("🗑");
        deleteButton.setForeground(ColorScheme.PROGRESS_ERROR_COLOR);
        deleteButton.setToolTipText("Delete this loadout");
        deleteButton.addActionListener(e -> {
            int confirm = JOptionPane.showConfirmDialog(this,
                    "Delete loadout '" + name + "'?",
                    "Confirm Delete",
                    JOptionPane.YES_NO_OPTION);
            if (confirm == JOptionPane.YES_OPTION) {
                plugin.deleteLoadoutFromPanel(name);
            }
        });
        buttonsPanel.add(deleteButton);

        panel.add(buttonsPanel);

        panel.addMouseListener(new MouseAdapter() {
            @Override
            public void mouseEntered(MouseEvent e) {
                panel.setBackground(hoverColor);
                buttonsPanel.setBackground(hoverColor);
            }

            @Override
            public void mouseExited(MouseEvent e) {
                panel.setBackground(bgColor);
                buttonsPanel.setBackground(bgColor);
            }
        });

        return panel;
    }

    // ========== Constructor ==========

    public PrayerLoadoutsPanel(PrayerLoadoutsPlugin plugin) {
        // Disable PluginPanel's built-in scroll wrapping so we can have fixed header/footer
        super(false);
        this.plugin = plugin;

        setLayout(new BorderLayout());
        setBackground(ColorScheme.DARK_GRAY_COLOR);

        // Create reusable info panels
        noLoadoutsPanel = createInfoPanel(
                null, null,
                "No loadouts saved",
                "Enter a name above and<br>click 'Save Current' to save<br>your first loadout.");

        loginRequiredPanel = createInfoPanel(
                "🔒", null,
                "Login Required",
                "Please log in to manage<br>your prayer loadouts.");

        prayerPluginRequiredPanel = createInfoPanel(
                "⚠", new Color(255, 200, 0),
                "Prayer Plugin Required",
                "Please enable the <br><b>Prayer</b> core plugin to use<br>Prayer Loadouts.");

        // ===== HEADER SECTION (NORTH) =====
        // Contains: Title + Refresh button (always) + Save panel (when logged in)
        JPanel headerSection = new JPanel(new BorderLayout());
        headerSection.setBackground(ColorScheme.DARK_GRAY_COLOR);

        // Title bar at top of header
        headerSection.add(createHeaderSection(), BorderLayout.NORTH);

        // Save panel below title
        savePanel = createSavePanel();
        headerSection.add(savePanel, BorderLayout.SOUTH);

        // ===== CONTENT SECTION (CENTER) =====
        // Scrollable area containing loadouts or error messages
        scrollableContent = new JPanel();
        scrollableContent.setLayout(new BoxLayout(scrollableContent, BoxLayout.Y_AXIS));
        scrollableContent.setBorder(new EmptyBorder(5, 10, 5, 10));

        JScrollPane scrollPane = new JScrollPane(scrollableContent);
        scrollPane.setBorder(null);
        scrollPane.getVerticalScrollBar().setPreferredSize(new Dimension(8, 0));
        scrollPane.setVerticalScrollBarPolicy(ScrollPaneConstants.VERTICAL_SCROLLBAR_AS_NEEDED);
        scrollPane.setHorizontalScrollBarPolicy(ScrollPaneConstants.HORIZONTAL_SCROLLBAR_NEVER);

        // ===== FOOTER SECTION (SOUTH) =====
        footerSection = createFooterSection();

        // ===== ASSEMBLE LAYOUT =====
        add(headerSection, BorderLayout.NORTH);
        add(scrollPane, BorderLayout.CENTER);
        add(footerSection, BorderLayout.SOUTH);

        rebuild();
    }

    // ========== Rebuild Logic ==========

    public void rebuild() {
        // Only clear and rebuild the scrollable content - header and footer stay intact
        scrollableContent.removeAll();

        boolean isLoggedIn = plugin.isLoggedIn();
        boolean isPrayerPluginEnabled = plugin.isPrayerPluginEnabled();
        boolean canUsePlugin = isLoggedIn && isPrayerPluginEnabled;

        // Control visibility of save panel and footer
        savePanel.setVisible(canUsePlugin);
        footerSection.setVisible(canUsePlugin);

        if (!isPrayerPluginEnabled) {
            scrollableContent.add(prayerPluginRequiredPanel);
        } else if (!isLoggedIn) {
            scrollableContent.add(loginRequiredPanel);
        } else {
            Set<String> loadoutNames = plugin.getLoadoutNames();
            String activeLoadout = plugin.getActiveLoadoutName();

            if (loadoutNames.isEmpty()) {
                scrollableContent.add(noLoadoutsPanel);
            } else {
                for (String name : loadoutNames) {
                    boolean isActive = name.equals(activeLoadout);
                    scrollableContent.add(createLoadoutPanel(name, isActive));
                    scrollableContent.add(Box.createRigidArea(new Dimension(0, 5)));
                }
            }
        }

        // Refresh the UI
        scrollableContent.revalidate();
        scrollableContent.repaint();
        revalidate();
        repaint();
    }
}

package com.prayerloadouts;

import com.google.gson.Gson;
import com.google.gson.reflect.TypeToken;
import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.api.gameval.VarbitID;
import net.runelite.client.config.ConfigManager;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.lang.reflect.Type;
import java.util.HashMap;
import java.util.Map;
import java.util.Set;

/**
 * Manages loadout operations: save, load, delete, rename, and active detection.
 * All loadouts are stored in a single JSON config key.
 */
@Singleton
public class LoadoutManager {
    static final String CONFIG_GROUP = "prayerloadouts";
    static final String PRAYER_CONFIG_GROUP = "prayer";
    static final String PRAYER_ORDER_KEY_PREFIX = "prayer_order_book_";
    static final String PRAYER_HIDDEN_KEY_PREFIX = "prayer_hidden_book_";
    private static final String LOADOUTS_KEY = "loadouts";
    static final String LAST_LOADOUT_KEY = "last_loadout";

    private static final Type LOADOUTS_TYPE = new TypeToken<Map<String, LoadoutData>>() {}.getType();

    private final Client client;
    private final ConfigManager configManager;
    private final PrayerStateManager prayerStateManager;
    private final Gson gson;

    private volatile String cachedFilterFingerprint = "";
    private volatile int cachedPrayerbook = 0;

    @Inject
    public LoadoutManager(Client client, ConfigManager configManager,
            PrayerStateManager prayerStateManager, Gson gson) {
        this.client = client;
        this.configManager = configManager;
        this.prayerStateManager = prayerStateManager;
        this.gson = gson;
    }

    public void updateCachedFilters() {
        int prayerbook = client.getVarbitValue(VarbitID.PRAYERBOOK);
        cachedPrayerbook = prayerbook;
        cachedFilterFingerprint = getCurrentFilterFingerprint();
    }

    private String getCurrentFilterFingerprint() {
        return client.getVarbitValue(VarbitID.PRAYER_FILTER_BLOCKLOWTIER) + ","
                + client.getVarbitValue(VarbitID.PRAYER_FILTER_ALLOWCOMBINEDTIER) + ","
                + client.getVarbitValue(VarbitID.PRAYER_FILTER_BLOCKHEALING) + ","
                + client.getVarbitValue(VarbitID.PRAYER_FILTER_BLOCKLACKLEVEL) + ","
                + client.getVarbitValue(VarbitID.PRAYER_FILTER_BLOCKLOCKED) + ","
                + client.getVarbitValue(VarbitID.PRAYER_HIDEFILTERBUTTON);
    }

    /**
     * Gets all loadouts from config.
     */
    public Map<String, LoadoutData> getAllLoadouts() {
        String json = configManager.getConfiguration(CONFIG_GROUP, LOADOUTS_KEY);
        if (json == null || json.isEmpty()) {
            return new HashMap<>();
        }
        try {
            Map<String, LoadoutData> loadouts = gson.fromJson(json, LOADOUTS_TYPE);
            return loadouts != null ? loadouts : new HashMap<>();
        } catch (Exception e) {
            return new HashMap<>();
        }
    }

    /**
     * Saves all loadouts to config.
     */
    private void saveAllLoadouts(Map<String, LoadoutData> loadouts) {
        if (loadouts.isEmpty()) {
            configManager.unsetConfiguration(CONFIG_GROUP, LOADOUTS_KEY);
        } else {
            String json = gson.toJson(loadouts, LOADOUTS_TYPE);
            configManager.setConfiguration(CONFIG_GROUP, LOADOUTS_KEY, json);
        }
    }

    /**
     * Gets a single loadout by name.
     */
    public LoadoutData getLoadout(String name) {
        return getAllLoadouts().get(name);
    }

    public Set<String> getLoadoutNames() {
        return getAllLoadouts().keySet();
    }

    String toSafeKey(String name) {
        if (name == null) {
            return "";
        }
        return name.toLowerCase().replaceAll("[^a-z0-9]", "_");
    }

    public void saveLoadout(String name) {
        if (client.getGameState() != GameState.LOGGED_IN || !prayerStateManager.isPrayerPluginEnabled()
                || name == null || name.trim().isEmpty()) {
            return;
        }

        int prayerbook = client.getVarbitValue(VarbitID.PRAYERBOOK);

        // Get or create loadout data
        Map<String, LoadoutData> loadouts = getAllLoadouts();
        LoadoutData loadout = loadouts.getOrDefault(name, new LoadoutData(name));
        loadout.setDisplayName(name);

        // Save prayer order
        String currentOrder = configManager.getConfiguration(
                PRAYER_CONFIG_GROUP,
                PRAYER_ORDER_KEY_PREFIX + prayerbook);
        String orderValue = (currentOrder == null || currentOrder.isEmpty()) ? "DEFAULT" : currentOrder;
        loadout.setPrayerOrder(prayerbook, orderValue);

        // Save filter settings
        LoadoutData.FilterSettings filters = new LoadoutData.FilterSettings(
                client.getVarbitValue(VarbitID.PRAYER_FILTER_BLOCKLOWTIER),
                client.getVarbitValue(VarbitID.PRAYER_FILTER_ALLOWCOMBINEDTIER),
                client.getVarbitValue(VarbitID.PRAYER_FILTER_BLOCKHEALING),
                client.getVarbitValue(VarbitID.PRAYER_FILTER_BLOCKLACKLEVEL),
                client.getVarbitValue(VarbitID.PRAYER_FILTER_BLOCKLOCKED),
                client.getVarbitValue(VarbitID.PRAYER_HIDEFILTERBUTTON)
        );
        loadout.setFilters(prayerbook, filters);

        // Save hidden prayers
        Map<String, String> hiddenPrayers = prayerStateManager.getCurrentHiddenPrayers(prayerbook);
        loadout.setHiddenPrayers(prayerbook, hiddenPrayers);

        // Save to config
        loadouts.put(name, loadout);
        saveAllLoadouts(loadouts);

        // Update last loaded loadout
        configManager.setConfiguration(CONFIG_GROUP, LAST_LOADOUT_KEY, name);
    }

    /**
     * Loads a loadout by name.
     * @return true if successful, false if no data exists for current prayerbook
     */
    public boolean loadLoadout(String name) {
        return loadLoadout(name, null);
    }

    /**
     * Loads a loadout by name with an optional completion callback.
     * @param name Loadout name to load
     * @param onComplete Optional callback to run after loadout is fully loaded (on client thread)
     * @return true if successful, false if no data exists for current prayerbook
     */
    public boolean loadLoadout(String name, Runnable onComplete) {
        if (client.getGameState() != GameState.LOGGED_IN || !prayerStateManager.isPrayerPluginEnabled()) {
            return false;
        }

        LoadoutData loadout = getLoadout(name);
        if (loadout == null) {
            return false;
        }

        int prayerbook = client.getVarbitValue(VarbitID.PRAYERBOOK);

        if (!loadout.hasPrayerOrder(prayerbook)) {
            return false;
        }

        String savedOrder = loadout.getPrayerOrder(prayerbook);

        // Restore prayer order
        if ("DEFAULT".equals(savedOrder)) {
            configManager.unsetConfiguration(PRAYER_CONFIG_GROUP, PRAYER_ORDER_KEY_PREFIX + prayerbook);
        } else {
            configManager.setConfiguration(
                    PRAYER_CONFIG_GROUP,
                    PRAYER_ORDER_KEY_PREFIX + prayerbook,
                    savedOrder);
        }

        // Restore hidden prayers
        prayerStateManager.loadHiddenPrayers(loadout.getHiddenPrayers(prayerbook), prayerbook);

        // Load filters and chain the completion callback
        LoadoutData.FilterSettings filters = loadout.getFilters(prayerbook);
        prayerStateManager.loadPrayerFilters(filters, () -> {
            updateCachedFilters();
            if (onComplete != null) {
                onComplete.run();
            }
        });

        // Update last loaded loadout
        configManager.setConfiguration(CONFIG_GROUP, LAST_LOADOUT_KEY, name);
        return true;
    }

    public void deleteLoadout(String name) {
        if (name == null || name.trim().isEmpty()) {
            return;
        }

        Map<String, LoadoutData> loadouts = getAllLoadouts();
        if (!loadouts.containsKey(name)) {
            return;
        }

        loadouts.remove(name);
        saveAllLoadouts(loadouts);
    }

    public void renameLoadout(String oldName, String newName) {
        if (oldName == null || newName == null || oldName.trim().isEmpty() || newName.trim().isEmpty()) {
            return;
        }

        Map<String, LoadoutData> loadouts = getAllLoadouts();
        if (!loadouts.containsKey(oldName) || loadouts.containsKey(newName)) {
            return;
        }

        LoadoutData loadout = loadouts.remove(oldName);
        loadout.setDisplayName(newName);
        loadouts.put(newName, loadout);
        saveAllLoadouts(loadouts);
    }

    public String getActiveLoadoutName(boolean isLoggedIn) {
        if (!isLoggedIn) {
            return null;
        }

        int prayerbook = cachedPrayerbook;
        String currentOrder = configManager.getConfiguration(
                PRAYER_CONFIG_GROUP,
                PRAYER_ORDER_KEY_PREFIX + prayerbook);
        boolean isDefaultOrder = (currentOrder == null || currentOrder.isEmpty());
        String currentHiddenFingerprint = prayerStateManager.getHiddenPrayersFingerprint(prayerbook);
        String currentFilterFingerprint = cachedFilterFingerprint;

        // First, check if the last loaded loadout still matches (prioritize it)
        String lastLoadout = getLastLoadoutName();
        Map<String, LoadoutData> loadouts = getAllLoadouts();

        if (lastLoadout != null && loadouts.containsKey(lastLoadout)) {
            if (loadoutMatchesCurrent(loadouts.get(lastLoadout), prayerbook, isDefaultOrder, currentOrder,
                    currentHiddenFingerprint, currentFilterFingerprint)) {
                return lastLoadout;
            }
        }

        // Fall back to finding any matching loadout
        for (Map.Entry<String, LoadoutData> entry : loadouts.entrySet()) {
            if (loadoutMatchesCurrent(entry.getValue(), prayerbook, isDefaultOrder, currentOrder,
                    currentHiddenFingerprint, currentFilterFingerprint)) {
                return entry.getKey();
            }
        }

        return null;
    }

    private boolean loadoutMatchesCurrent(LoadoutData loadout, int prayerbook, boolean isDefaultOrder,
            String currentOrder, String currentHiddenFingerprint, String currentFilterFingerprint) {

        String savedOrder = loadout.getPrayerOrder(prayerbook);
        if (savedOrder == null) {
            return false;
        }

        boolean orderMatches = isDefaultOrder
                ? "DEFAULT".equals(savedOrder)
                : currentOrder.equals(savedOrder);

        if (!orderMatches) {
            return false;
        }

        String savedHiddenFingerprint = getHiddenPrayersFingerprint(loadout.getHiddenPrayers(prayerbook));
        if (!currentHiddenFingerprint.equals(savedHiddenFingerprint)) {
            return false;
        }

        LoadoutData.FilterSettings filters = loadout.getFilters(prayerbook);
        String savedFilterFingerprint = filters != null ? filters.toFingerprint() : "0,0,0,0,0,0";
        return currentFilterFingerprint.equals(savedFilterFingerprint);
    }

    private String getHiddenPrayersFingerprint(Map<String, String> hiddenPrayers) {
        if (hiddenPrayers == null || hiddenPrayers.isEmpty()) {
            return "";
        }

        StringBuilder sb = new StringBuilder();
        hiddenPrayers.entrySet().stream()
                .sorted(Map.Entry.comparingByKey())
                .forEach(entry -> sb.append(entry.getKey()).append("=").append(entry.getValue()).append(";"));
        return sb.toString();
    }

    public String getLastLoadoutName() {
        return configManager.getConfiguration(CONFIG_GROUP, LAST_LOADOUT_KEY);
    }

    public void resetToDefaults() {
        if (client.getGameState() != GameState.LOGGED_IN || !prayerStateManager.isPrayerPluginEnabled()) {
            return;
        }

        int prayerbook = client.getVarbitValue(VarbitID.PRAYERBOOK);
        prayerStateManager.resetToDefaults(prayerbook);
        configManager.unsetConfiguration(CONFIG_GROUP, LAST_LOADOUT_KEY);
    }

    /**
     * Saves a loadout directly (used by import).
     */
    public void saveLoadoutData(String name, LoadoutData loadout) {
        Map<String, LoadoutData> loadouts = getAllLoadouts();
        loadouts.put(name, loadout);
        saveAllLoadouts(loadouts);
    }
}

package com.prayerloadouts;

import net.runelite.api.Client;
import net.runelite.api.gameval.InterfaceID;
import net.runelite.api.gameval.VarbitID;
import net.runelite.api.widgets.Widget;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.plugins.PluginManager;
import net.runelite.client.plugins.prayer.PrayerPlugin;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.util.HashMap;
import java.util.Map;

/**
 * Manages prayer-specific state including hidden prayers, filter settings, and
 * UI refresh.
 */
@Singleton
public class PrayerStateManager {

    private final Client client;
    private final ClientThread clientThread;
    private final ConfigManager configManager;
    private final PluginManager pluginManager;
    private final PrayerPlugin prayerPlugin;

    @Inject
    public PrayerStateManager(Client client, ClientThread clientThread,
            ConfigManager configManager, PluginManager pluginManager,
            PrayerPlugin prayerPlugin) {
        this.client = client;
        this.clientThread = clientThread;
        this.configManager = configManager;
        this.pluginManager = pluginManager;
        this.prayerPlugin = prayerPlugin;
    }

    public boolean isPrayerPluginEnabled() {
        return pluginManager.isPluginEnabled(prayerPlugin);
    }

    /**
     * Gets the current hidden prayers from the Prayer plugin's config.
     * @return Map of prayer key to hidden value
     */
    public Map<String, String> getCurrentHiddenPrayers(int prayerbook) {
        Map<String, String> hiddenPrayers = new HashMap<>();
        String prefix = LoadoutManager.PRAYER_CONFIG_GROUP + "." + LoadoutManager.PRAYER_HIDDEN_KEY_PREFIX + prayerbook;

        for (String key : configManager.getConfigurationKeys(prefix)) {
            String[] parts = key.split("\\.", 2);
            if (parts.length == 2) {
                String value = configManager.getConfiguration(parts[0], parts[1]);
                // Extract the prayer-specific part of the key (after the prefix)
                String prayerKey = parts[1].substring(LoadoutManager.PRAYER_HIDDEN_KEY_PREFIX.length() + 1);
                hiddenPrayers.put(prayerKey, value);
            }
        }

        return hiddenPrayers;
    }

    /**
     * Gets a fingerprint of the current hidden prayers for comparison.
     */
    public String getHiddenPrayersFingerprint(int prayerbook) {
        Map<String, String> hiddenPrayers = getCurrentHiddenPrayers(prayerbook);
        if (hiddenPrayers.isEmpty()) {
            return "";
        }

        StringBuilder sb = new StringBuilder();
        hiddenPrayers.entrySet().stream()
                .sorted(Map.Entry.comparingByKey())
                .forEach(entry -> sb.append(entry.getKey()).append("=").append(entry.getValue()).append(";"));
        return sb.toString();
    }

    /**
     * Loads hidden prayers from a map into the Prayer plugin's config.
     */
    public void loadHiddenPrayers(Map<String, String> hiddenPrayers, int prayerbook) {
        // Clear current hidden prayers
        String currentPrefix = LoadoutManager.PRAYER_CONFIG_GROUP + "." + LoadoutManager.PRAYER_HIDDEN_KEY_PREFIX + prayerbook;
        for (String key : configManager.getConfigurationKeys(currentPrefix)) {
            String[] parts = key.split("\\.", 2);
            if (parts.length == 2) {
                configManager.unsetConfiguration(parts[0], parts[1]);
            }
        }

        // Restore hidden prayers from the provided map
        if (hiddenPrayers != null) {
            for (Map.Entry<String, String> entry : hiddenPrayers.entrySet()) {
                String configKey = LoadoutManager.PRAYER_HIDDEN_KEY_PREFIX + prayerbook + entry.getKey();
                configManager.setConfiguration(LoadoutManager.PRAYER_CONFIG_GROUP, configKey, entry.getValue());
            }
        }
    }

    /**
     * Loads prayer filter settings from FilterSettings object.
     * @param filters Filter settings to apply (can be null for defaults)
     * @param onComplete Optional callback to run after varbits are set (on client thread)
     */
    public void loadPrayerFilters(LoadoutData.FilterSettings filters, Runnable onComplete) {
        clientThread.invokeLater(() -> {
            if (filters != null) {
                client.setVarbit(VarbitID.PRAYER_FILTER_BLOCKLOWTIER, filters.getBlockLowTier());
                client.setVarbit(VarbitID.PRAYER_FILTER_ALLOWCOMBINEDTIER, filters.getAllowCombinedTier());
                client.setVarbit(VarbitID.PRAYER_FILTER_BLOCKHEALING, filters.getBlockHealing());
                client.setVarbit(VarbitID.PRAYER_FILTER_BLOCKLACKLEVEL, filters.getBlockLackLevel());
                client.setVarbit(VarbitID.PRAYER_FILTER_BLOCKLOCKED, filters.getBlockLocked());
                client.setVarbit(VarbitID.PRAYER_HIDEFILTERBUTTON, filters.getHideFilterButton());
            }

            // Redraw after setting all varbits to update the filter UI
            redrawPrayers();

            // Run callback after varbits are set and UI is updated
            if (onComplete != null) {
                onComplete.run();
            }
        });
    }

    public void redrawPrayers() {
        Widget prayerWidget = client.getWidget(InterfaceID.PRAYERBOOK, 0);
        if (prayerWidget != null) {
            client.runScript(prayerWidget.getOnVarTransmitListener());
        }
    }

    public void resetToDefaults(int prayerbook) {
        // Clear prayer order configuration
        configManager.unsetConfiguration(
                LoadoutManager.PRAYER_CONFIG_GROUP,
                LoadoutManager.PRAYER_ORDER_KEY_PREFIX + prayerbook);

        // Clear hidden prayers configuration
        for (String key : configManager.getConfigurationKeys(
                LoadoutManager.PRAYER_CONFIG_GROUP + "." + LoadoutManager.PRAYER_HIDDEN_KEY_PREFIX + prayerbook)) {
            String[] parts = key.split("\\.", 2);
            if (parts.length == 2) {
                configManager.unsetConfiguration(parts[0], parts[1]);
            }
        }

        // Reset filter varbits to defaults on the client thread
        clientThread.invokeLater(() -> {
            client.setVarbit(VarbitID.PRAYER_FILTER_BLOCKLOWTIER, 0);
            client.setVarbit(VarbitID.PRAYER_FILTER_BLOCKHEALING, 0);
            client.setVarbit(VarbitID.PRAYER_FILTER_BLOCKLACKLEVEL, 0);
            client.setVarbit(VarbitID.PRAYER_FILTER_BLOCKLOCKED, 0);
            client.setVarbit(VarbitID.PRAYER_HIDEFILTERBUTTON, 0);

            // Redraw to update the filter UI after setting all varbits
            redrawPrayers();
        });
    }
}

package com.prayerloadouts;

import java.util.HashMap;
import java.util.Map;

/**
 * Data model for a single prayer loadout.
 * Designed for JSON serialization via Gson.
 */
public class LoadoutData {
    /**
     * Display name of the loadout (preserves original capitalization).
     */
    String displayName;

    /**
     * Prayer order strings per prayerbook.
     * Value is "DEFAULT" if using vanilla order, or comma-separated prayer IDs.
     */
    Map<Integer, String> prayerOrders = new HashMap<>();

    /**
     * Filter settings per prayerbook.
     */
    Map<Integer, FilterSettings> filters = new HashMap<>();

    /**
     * Hidden prayers per prayerbook.
     * Maps prayerbook -> (prayer key -> hidden value).
     */
    Map<Integer, Map<String, String>> hiddenPrayers = new HashMap<>();

    public LoadoutData() {
    }

    public LoadoutData(String displayName) {
        this.displayName = displayName;
    }

    public String getDisplayName() {
        return displayName;
    }

    public void setDisplayName(String displayName) {
        this.displayName = displayName;
    }

    public String getPrayerOrder(int prayerbook) {
        return prayerOrders.get(prayerbook);
    }

    public void setPrayerOrder(int prayerbook, String order) {
        prayerOrders.put(prayerbook, order);
    }

    public boolean hasPrayerOrder(int prayerbook) {
        String order = prayerOrders.get(prayerbook);
        return order != null && !order.isEmpty();
    }

    public FilterSettings getFilters(int prayerbook) {
        return filters.get(prayerbook);
    }

    public void setFilters(int prayerbook, FilterSettings filterSettings) {
        filters.put(prayerbook, filterSettings);
    }

    public Map<String, String> getHiddenPrayers(int prayerbook) {
        return hiddenPrayers.getOrDefault(prayerbook, new HashMap<>());
    }

    public void setHiddenPrayers(int prayerbook, Map<String, String> hidden) {
        hiddenPrayers.put(prayerbook, hidden);
    }

    /**
     * Filter settings for a prayerbook.
     */
    public static class FilterSettings {
        int blockLowTier;
        int allowCombinedTier;
        int blockHealing;
        int blockLackLevel;
        int blockLocked;
        int hideFilterButton;

        public FilterSettings() {
        }

        public FilterSettings(int blockLowTier, int allowCombinedTier, int blockHealing,
                              int blockLackLevel, int blockLocked, int hideFilterButton) {
            this.blockLowTier = blockLowTier;
            this.allowCombinedTier = allowCombinedTier;
            this.blockHealing = blockHealing;
            this.blockLackLevel = blockLackLevel;
            this.blockLocked = blockLocked;
            this.hideFilterButton = hideFilterButton;
        }

        public String toFingerprint() {
            return blockLowTier + "," + allowCombinedTier + "," + blockHealing + ","
                    + blockLackLevel + "," + blockLocked + "," + hideFilterButton;
        }

        public int getBlockLowTier() {
            return blockLowTier;
        }

        public int getAllowCombinedTier() {
            return allowCombinedTier;
        }

        public int getBlockHealing() {
            return blockHealing;
        }

        public int getBlockLackLevel() {
            return blockLackLevel;
        }

        public int getBlockLocked() {
            return blockLocked;
        }

        public int getHideFilterButton() {
            return hideFilterButton;
        }
    }
}

package com.prayerloadouts;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.awt.Toolkit;
import java.awt.datatransfer.DataFlavor;
import java.awt.datatransfer.StringSelection;
import java.awt.datatransfer.UnsupportedFlavorException;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

/**
 * Handles export and import of loadouts via the system clipboard.
 */
@Singleton
public class LoadoutSerializer {
    private final LoadoutManager loadoutManager;

    @Inject
    public LoadoutSerializer(LoadoutManager loadoutManager) {
        this.loadoutManager = loadoutManager;
    }

    /**
     * Exports a loadout to clipboard.
     * @return true if data was exported, false if loadout has no data
     */
    public boolean exportLoadout(String name) {
        LoadoutData loadout = loadoutManager.getLoadout(name);
        if (loadout == null) {
            return false;
        }

        StringBuilder export = new StringBuilder();
        export.append("PRAYERLOADOUT:").append(name).append("\n");

        boolean hasData = false;
        for (int prayerbook = 0; prayerbook <= 1; prayerbook++) {
            String order = loadout.getPrayerOrder(prayerbook);

            if (order != null && !order.isEmpty()) {
                hasData = true;
                export.append("ORDER_").append(prayerbook).append(":").append(order).append("\n");

                // Export filter settings
                LoadoutData.FilterSettings filters = loadout.getFilters(prayerbook);
                if (filters != null) {
                    export.append("FILTER_").append(prayerbook).append("_blocklowtier:")
                            .append(filters.getBlockLowTier()).append("\n");
                    export.append("FILTER_").append(prayerbook).append("_allowcombinedtier:")
                            .append(filters.getAllowCombinedTier()).append("\n");
                    export.append("FILTER_").append(prayerbook).append("_blockhealing:")
                            .append(filters.getBlockHealing()).append("\n");
                    export.append("FILTER_").append(prayerbook).append("_blocklacklevel:")
                            .append(filters.getBlockLackLevel()).append("\n");
                    export.append("FILTER_").append(prayerbook).append("_blocklocked:")
                            .append(filters.getBlockLocked()).append("\n");
                    export.append("FILTER_").append(prayerbook).append("_hidefilterbutton:")
                            .append(filters.getHideFilterButton()).append("\n");
                }

                // Export hidden prayers
                Map<String, String> hiddenPrayers = loadout.getHiddenPrayers(prayerbook);
                if (hiddenPrayers != null) {
                    for (Map.Entry<String, String> entry : hiddenPrayers.entrySet()) {
                        export.append("HIDDEN_").append(prayerbook).append("_").append(entry.getKey())
                                .append(":").append(entry.getValue()).append("\n");
                    }
                }
            }
        }

        if (!hasData) {
            return false;
        }

        export.append("END");

        try {
            Toolkit.getDefaultToolkit()
                    .getSystemClipboard()
                    .setContents(new StringSelection(export.toString()), null);
            return true;
        } catch (Exception ignored) {
            return false;
        }
    }

    /**
     * Imports a loadout from clipboard data.
     * @param importName Name to use for the imported loadout (null/empty to use original name)
     * @return true if import was successful, false otherwise
     */
    public boolean importLoadout(String importName) {
        String clipboardData;
        try {
            clipboardData = (String) Toolkit.getDefaultToolkit()
                    .getSystemClipboard()
                    .getData(DataFlavor.stringFlavor);
        } catch (UnsupportedFlavorException | IOException e) {
            return false;
        }

        // Validate clipboard data format
        if (clipboardData == null || !clipboardData.startsWith("PRAYERLOADOUT:")) {
            return false;
        }

        if (!clipboardData.contains("\nEND")) {
            return false;
        }

        String[] lines = clipboardData.split("\n");
        if (lines.length < 2) {
            return false;
        }

        // Extract and validate original name
        String originalName = lines[0].substring("PRAYERLOADOUT:".length());
        if (originalName.isEmpty() || originalName.contains(",")) {
            return false;
        }

        // Use provided name or fall back to original
        if (importName == null || importName.trim().isEmpty()) {
            importName = originalName;
        } else {
            importName = importName.trim();
        }

        // Create new LoadoutData
        LoadoutData loadout = new LoadoutData(importName);

        // Temporary storage for filter values during parsing
        Map<Integer, int[]> filterValues = new HashMap<>();

        // Parse and import loadout data
        for (int i = 1; i < lines.length; i++) {
            String line = lines[i].trim();
            if (line.equals("END")) {
                break;
            }

            int colonIndex = line.indexOf(':');
            if (colonIndex == -1) {
                continue;
            }

            String key = line.substring(0, colonIndex);
            String value = line.substring(colonIndex + 1);

            try {
                if (key.startsWith("ORDER_")) {
                    int prayerbook = Integer.parseInt(key.substring("ORDER_".length()));
                    loadout.setPrayerOrder(prayerbook, value);
                } else if (key.startsWith("FILTER_")) {
                    String rest = key.substring("FILTER_".length());
                    int underscoreIdx = rest.indexOf('_');
                    if (underscoreIdx == -1) {
                        continue;
                    }
                    int prayerbook = Integer.parseInt(rest.substring(0, underscoreIdx));
                    String filterKey = rest.substring(underscoreIdx + 1);
                    int filterValue = Integer.parseInt(value);

                    // Store filter values temporarily
                    int[] filters = filterValues.computeIfAbsent(prayerbook, k -> new int[6]);
                    switch (filterKey) {
                        case "blocklowtier":
                            filters[0] = filterValue;
                            break;
                        case "allowcombinedtier":
                            filters[1] = filterValue;
                            break;
                        case "blockhealing":
                            filters[2] = filterValue;
                            break;
                        case "blocklacklevel":
                            filters[3] = filterValue;
                            break;
                        case "blocklocked":
                            filters[4] = filterValue;
                            break;
                        case "hidefilterbutton":
                            filters[5] = filterValue;
                            break;
                    }
                } else if (key.startsWith("HIDDEN_")) {
                    String rest = key.substring("HIDDEN_".length());
                    int underscoreIdx = rest.indexOf('_');
                    if (underscoreIdx == -1) {
                        continue;
                    }
                    int prayerbook = Integer.parseInt(rest.substring(0, underscoreIdx));
                    String hiddenKey = rest.substring(underscoreIdx + 1);

                    Map<String, String> hiddenPrayers = loadout.getHiddenPrayers(prayerbook);
                    if (hiddenPrayers.isEmpty()) {
                        hiddenPrayers = new HashMap<>();
                    }
                    hiddenPrayers.put(hiddenKey, value);
                    loadout.setHiddenPrayers(prayerbook, hiddenPrayers);
                }
            } catch (NumberFormatException e) {
                // Skip invalid lines
                continue;
            }
        }

        // Convert temporary filter arrays to FilterSettings objects
        for (Map.Entry<Integer, int[]> entry : filterValues.entrySet()) {
            int[] f = entry.getValue();
            LoadoutData.FilterSettings filters = new LoadoutData.FilterSettings(
                    f[0], f[1], f[2], f[3], f[4], f[5]
            );
            loadout.setFilters(entry.getKey(), filters);
        }

        // Save the loadout
        loadoutManager.saveLoadoutData(importName, loadout);
        return true;
    }
}

