package org.asundr;

import java.awt.*;

public class HighlightDefinition
{
    private final int id;
    private Color color;
    private boolean notify;
    private transient String name;
    public HighlightDefinition(int id, Color color, boolean notify)
    {
        this.id = id;
        this. color = color;
        this.notify = notify;
    }
    public int getId() { return id; }
    public boolean getNotify() { return notify; }
    public void setNotify(final boolean newNotify) { this.notify = newNotify; }
    public Color getColor() { return color; }
    public void setColor(final Color color) { this.color = color; }
    public String getName() { return name; }
    public void setName(final String name) { this.name = name; }
}

