@ConfigGroup("deathIndicator")
public interface DeathIndicatorConfig extends Config
{
	@ConfigItem(
		position = 1,
		keyName = "deathHintArrow",
		name = "Death Hint Arrow",
		description = "Configures whether or not to show a hint arrow to death location"
